        public void LoadFunc()
        {
            //txtCustomerSearch.Enabled = true;
            //pctCusClose.Visible = false;
            txtCustomerSearch.Text = "";
            //pctCustomerSearch.Visible = true;
            txtDays.Text = "";
            Cursor.Current = Cursors.WaitCursor;
            cmbCustomerType.SelectedIndex = 0;
            LoadCust();
            cmbFilterInvoice.SelectedIndex = 0;
            cmbTransactionsFilterDate.SelectedIndex = 0;
            cmbPendingInvoiceFilter.SelectedIndex = 0;
            cmbPendingInvoicedate.SelectedIndex = 0;
            cmbInvoiceManageTransactions.SelectedIndex = 0;
            //cmbRunReport.SelectedIndex = 0;
            cmbInvoiceFilter.SelectedIndex = 0;
            //cmbInvoiceDate.SelectedIndex = 0;
            if (cmbFilterInvoice.SelectedIndex >= 0)
            {
                if (dgvCustomerList.Rows.Count > 0)
                {
                    try
                    {
                        if (dgvCustomerList.Rows[CustRowIndex].Cells["ID"].Value.ToString() != null)
                            CustomerWiseInvoiceLoad(Convert.ToInt32(dgvCustomerList.Rows[CustRowIndex].Cells["ID"].Value.ToString()));
                    }
                    catch (Exception ex)
                    {
                        ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter,Function :LoadFunc. Message:" + ex.Message);
                        MessageBox.Show("Error:" + ex.Message);
                    }
                }
            }
            if (cmbPendingInvoiceFilter.SelectedIndex >= 0)
            {
                if (dgvCustomerList.Rows.Count > 0)
                {
                    try
                    {
                        if (dgvCustomerList.Rows[0].Cells["ID"].Value != null)
                            CustomerWisePandingInvoices(Convert.ToInt32(dgvCustomerList.Rows[0].Cells["ID"].Value.ToString()));
                    }
                    catch (Exception ex)
                    {
                        ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter,Function :LoadFunc. Message:" + ex.Message);
                        MessageBox.Show("Error:" + ex.Message);
                    }
                }
            }
            LoadAllInvoices();
            Cursor.Current = Cursors.Default;
            HideColumn();
        }
