        // All Customer List
        public void LoadCust()
        {
            try
            {
                bool ViewAll = false;
                if (ClsCommon.FunctionVisibility("ViewAllInvoice", "CustomerCenter"))
                {
                    ViewAll = true;
                }
                Cursor.Current = Cursors.WaitCursor;
                if (ClsCommon.FunctionVisibility("CustomerNumberOnly", "CustomerCenter"))
                {
                    if (cmbCustomerType.SelectedIndex == 1)
                    {
                        //Active Customer
                        dtCustomer = new DataTable();
                        if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                            dtCustomer = new BALCustomerMaster().SelectActiveCustomer(new BOLCustomerMaster() { SalesRepID = 0, IsCustomerNumber = 0 });
                        else if (ViewAll == true)
                        {
                            dtCustomer = new BALCustomerMaster().SelectActiveCustomer(new BOLCustomerMaster() { SalesRepID = 0, IsCustomerNumber = 1 });
                        }
                        else
                            dtCustomer = new BALCustomerMaster().SelectActiveCustomer(new BOLCustomerMaster() { SalesRepID = ClsCommon.UserID, IsCustomerNumber = 1 });
                    }
                    else if (cmbCustomerType.SelectedIndex == 0)
                    {
                        // All Customer
                        dtCustomer = new DataTable();
                        if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                            dtCustomer = new BALCustomerMaster().Select(new BOLCustomerMaster() { SalesRepID = 0, IsCustomerNumber = 0 });
                        else if (ViewAll == true)
                        {
                            dtCustomer = new BALCustomerMaster().Select(new BOLCustomerMaster() { SalesRepID = 0, IsCustomerNumber = 1 });
                        }
                        else
                            dtCustomer = new BALCustomerMaster().Select(new BOLCustomerMaster() { SalesRepID = ClsCommon.UserID, IsCustomerNumber = 1 });
                    }
                    else if (cmbCustomerType.SelectedIndex == 2)
                    {
                        // OpenBalance Customer
                        dtCustomer = new DataTable();
                        if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                            dtCustomer = new BALCustomerMaster().SelectOpenBalanceCustomer(new BOLCustomerMaster() { SalesRepID = 0, IsCustomerNumber = 0 });
                        else if (ViewAll == true)
                        {
                            dtCustomer = new BALCustomerMaster().SelectOpenBalanceCustomer(new BOLCustomerMaster() { SalesRepID = 0, IsCustomerNumber = 1 });
                        }
                        else
                            dtCustomer = new BALCustomerMaster().SelectOpenBalanceCustomer(new BOLCustomerMaster() { SalesRepID = ClsCommon.UserID, IsCustomerNumber = 1 });

                    }
                    else if (cmbCustomerType.SelectedIndex == 3)
                    {
                        //OverDueInvoices Customer
                        dtCustomer = new DataTable();
                        if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                            dtCustomer = new BALCustomerMaster().SelectCustomerWithOverDueInvoices(new BOLCustomerMaster() { SalesRepID = 0, IsCustomerNumber = 0 });
                        else if (ViewAll == true)
                        {
                            dtCustomer = new BALCustomerMaster().SelectCustomerWithOverDueInvoices(new BOLCustomerMaster() { SalesRepID = 0, IsCustomerNumber = 1 });
                        }
                        else
                            dtCustomer = new BALCustomerMaster().SelectCustomerWithOverDueInvoices(new BOLCustomerMaster() { SalesRepID = ClsCommon.UserID, IsCustomerNumber = 1 });
                    }
                    else if (cmbCustomerType.SelectedIndex == 4)
                    {
                        //OverDueInvoices Customer
                        dtCustomer = new DataTable();
                        if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                            dtCustomer = new BALCustomerMaster().SelectForNewCustomer(new BOLCustomerMaster() { SalesRepID = 0, IsCustomerNumber = 0 });
                        else if (ViewAll == true)
                        {
                            dtCustomer = new BALCustomerMaster().SelectForNewCustomer(new BOLCustomerMaster() { SalesRepID = 0, IsCustomerNumber = 1 });
                        }
                        else
                            dtCustomer = new BALCustomerMaster().SelectForNewCustomer(new BOLCustomerMaster() { SalesRepID = ClsCommon.UserID, IsCustomerNumber = 1 });
                    }
                }
                else
                {
                    if (cmbCustomerType.SelectedIndex == 1)
                    {
                        //Active Customer
                        dtCustomer = new DataTable();
                        if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                            dtCustomer = new BALCustomerMaster().SelectActiveCustomer(new BOLCustomerMaster() { SalesRepID = 0, IsCustomerNumber = 0 });
                        else if (ViewAll == true)
                        {
                            dtCustomer = new BALCustomerMaster().SelectActiveCustomer(new BOLCustomerMaster() { SalesRepID = 0, IsCustomerNumber = 1 });
                        }
                        else
                            dtCustomer = new BALCustomerMaster().SelectActiveCustomer(new BOLCustomerMaster() { SalesRepID = ClsCommon.UserID, IsCustomerNumber = 0 });
                    }
                    else if (cmbCustomerType.SelectedIndex == 0)
                    {
                        // All Customer
                        dtCustomer = new DataTable();
                        if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                            dtCustomer = new BALCustomerMaster().Select(new BOLCustomerMaster() { SalesRepID = 0, IsCustomerNumber = 0 });
                        else if (ViewAll == true)
                        {
                            dtCustomer = new BALCustomerMaster().Select(new BOLCustomerMaster() { SalesRepID = 0, IsCustomerNumber = 1 });
                        }
                        else
                            dtCustomer = new BALCustomerMaster().Select(new BOLCustomerMaster() { SalesRepID = ClsCommon.UserID, IsCustomerNumber = 0 });
                    }
                    else if (cmbCustomerType.SelectedIndex == 2)
                    {
                        // OpenBalance Customer
                        dtCustomer = new DataTable();
                        if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                            dtCustomer = new BALCustomerMaster().SelectOpenBalanceCustomer(new BOLCustomerMaster() { SalesRepID = 0, IsCustomerNumber = 0 });
                        else if (ViewAll == true)
                        {
                            dtCustomer = new BALCustomerMaster().SelectOpenBalanceCustomer(new BOLCustomerMaster() { SalesRepID = 0, IsCustomerNumber = 1 });
                        }
                        else
                            dtCustomer = new BALCustomerMaster().SelectOpenBalanceCustomer(new BOLCustomerMaster() { SalesRepID = ClsCommon.UserID, IsCustomerNumber = 0 });

                    }
                    else if (cmbCustomerType.SelectedIndex == 3)
                    {
                        //OverDueInvoices Customer
                        dtCustomer = new DataTable();
                        if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                            dtCustomer = new BALCustomerMaster().SelectCustomerWithOverDueInvoices(new BOLCustomerMaster() { SalesRepID = 0, IsCustomerNumber = 0 });
                        else if (ViewAll == true)
                        {
                            dtCustomer = new BALCustomerMaster().SelectCustomerWithOverDueInvoices(new BOLCustomerMaster() { SalesRepID = 0, IsCustomerNumber = 1 });
                        }
                        else
                            dtCustomer = new BALCustomerMaster().SelectCustomerWithOverDueInvoices(new BOLCustomerMaster() { SalesRepID = ClsCommon.UserID, IsCustomerNumber = 0 });
                    }
                    else if (cmbCustomerType.SelectedIndex == 4)
                    {
                        //OverDueInvoices Customer
                        dtCustomer = new DataTable();
                        if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                            dtCustomer = new BALCustomerMaster().SelectForNewCustomer(new BOLCustomerMaster() { SalesRepID = 0, IsCustomerNumber = 0 });
                        else if (ViewAll == true)
                        {
                            dtCustomer = new BALCustomerMaster().SelectForNewCustomer(new BOLCustomerMaster() { SalesRepID = 0, IsCustomerNumber = 1 });
                        }
                        else
                            dtCustomer = new BALCustomerMaster().SelectForNewCustomer(new BOLCustomerMaster() { SalesRepID = ClsCommon.UserID, IsCustomerNumber = 0 });
                    }
                }
                if (dtCustomer.Rows.Count > 0)
                {
                    int j = 0;
                    dgvCustomerList.Rows.Clear();
                    for (int i = 0; i < dtCustomer.Rows.Count; i++)
                    {
                        dgvCustomerList.Rows.Add();
                        dgvCustomerList.Rows[j].Cells[0].Value = dtCustomer.Rows[i]["ID"].ToString();
                        if (dtCustomer.Rows[i]["ActiveStatus"].ToString() == "InActive")
                            dgvCustomerList.Rows[j].Cells[1].Value = "X";
                        else
                            dgvCustomerList.Rows[j].Cells[1].Value = "";
                        dgvCustomerList.Rows[j].Cells[2].Value = dtCustomer.Rows[i]["Customer"].ToString();
                        if (dtCustomer.Rows[i]["BalanceTotal"].ToString() != null && dtCustomer.Rows[i]["BalanceTotal"].ToString() != "")
                            dgvCustomerList.Rows[j].Cells[3].Value = dtCustomer.Rows[i]["BalanceTotal"].ToString();
                        else
                            dgvCustomerList.Rows[j].Cells[3].Value = "0.00";
                        if (ClsCommon.UserType != "Admin" && ClsCommon.UserType != "admin")
                        {
                            if (dtCustomer.Rows[i]["SalesRepID"].ToString() == null || dtCustomer.Rows[i]["SalesRepID"].ToString() == "" || dtCustomer.Rows[i]["SalesRepID"].ToString() == "0")
                                dgvCustomerList.Rows[i].DefaultCellStyle.BackColor = Color.Silver;
                        }
                        if (dtCustomer.Rows[i]["SalesRepID"].ToString() != null || dtCustomer.Rows[i]["SalesRepID"].ToString() != "" || dtCustomer.Rows[i]["SalesRepID"].ToString() != "0" || dtCustomer.Rows[i]["SalesRepAll"].ToString() != "")
                        {
                            if (dtCustomer.Rows[i]["InvCount"].ToString() != "")
                            {
                                if (Convert.ToInt32(dtCustomer.Rows[i]["InvCount"].ToString()) <= 5)
                                {
                                    dgvCustomerList.Rows[i].DefaultCellStyle.BackColor = Color.LightYellow;
                                }
                            }
                            else
                            {
                                dgvCustomerList.Rows[i].DefaultCellStyle.BackColor = Color.LightYellow;
                            }
                        }
                        j++;
                    }
                    dgvCustomerList.Rows[CustRowIndex].Selected = true;
                    if (dtCustomer.Rows[0]["ID"].ToString() != "")
                    {
                        LoadCustomerData(Convert.ToInt32(dgvCustomerList.Rows[CustRowIndex].Cells["ID"].Value.ToString()));
                        DisplayLog(dgvCustomerList.Rows[CustRowIndex].Cells["ID"].Value.ToString());
                        DisplayNoteForCustomer(Convert.ToInt32(dgvCustomerList.Rows[CustRowIndex].Cells["ID"].Value.ToString()));
                    }


                }
                else
                    dgvCustomerList.Rows.Clear();
                lblTotal.Text = dtCustomer.Rows.Count.ToString();
                Cursor.Current = Cursors.Default;

            }
            catch (Exception ex)
            {
                Cursor.Current = Cursors.Default;
                ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter, Function :LoadCustomer. Message:" + ex.Message);
                MessageBox.Show("Error:" + ex.Message);
            }
        }
        public void LoadCustomer()
        {
            bool ViewAll = false;
            try
            {
                if (ClsCommon.FunctionVisibility("ViewAllCustomer", "CustomerCenter"))
                {
                    ViewAll = true;
                }
                if (ClsCommon.FunctionVisibility("CustomerNumberOnly", "CustomerCenter"))
                {
                    Cursor.Current = Cursors.WaitCursor;
                    if (cmbCustomerType.SelectedIndex == 1)
                    {
                        //Active Customer
                        dtCustomer = new DataTable();
                        if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                        {
                            dtCustomer = new BALCustomerMaster().SelectActiveCustomer(new BOLCustomerMaster() { SalesRepID = 0, IsCustomerNumber = 0 });
                        }
                        else
                        {
                            if (ViewAll == true)
                            {
                                dtCustomer = new BALCustomerMaster().SelectActiveCustomer(new BOLCustomerMaster() { SalesRepID = 0, IsCustomerNumber = 1 });

                            }
                            else
