                        DisplayNotes(ID);
                        DisplayNoteForCustomer(Convert.ToInt32(dgvCustomerList.Rows[0].Cells["ID"].Value.ToString()));
                    }
                }
                else
                    dgvCustomerList.Rows.Clear();
                lblTotal.Text = dtCustomer.Rows.Count.ToString();
                Cursor.Current = Cursors.Default;
            }
            catch (Exception ex)
            {
                Cursor.Current = Cursors.Default;
                ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter, Function :LoadCustomer. Message:" + ex.Message);
                MessageBox.Show("Error:" + ex.Message);
            }
