        public void CustomerSearch()
        {
            bool ViewAll = false;
            try
            {
                if (ClsCommon.FunctionVisibility("ViewAllCustomer", "CustomerCenter"))
                {
                    ViewAll = true;
                }
                if (ClsCommon.FunctionVisibility("CustomerNumberOnly", "CustomerCenter"))
                {
                    dtCustomer = new DataTable();

                    if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                    {
                        dtCustomer = new BALCustomerMaster().Search(new BOLCustomerMaster() { SalesRepID = 0, CustomerName = txtCustomerSearch.Text, IsCustomerNumber = 0 });
                    }
                    else
                    {
                        if (ViewAll == true)
                        {
                            dtCustomer = new BALCustomerMaster().Search(new BOLCustomerMaster() { SalesRepID = 0, CustomerName = txtCustomerSearch.Text, IsCustomerNumber = 1 });
                        }
                        else
                        {
                            dtCustomer = new BALCustomerMaster().Search(new BOLCustomerMaster() { SalesRepID = ClsCommon.UserID, CustomerName = txtCustomerSearch.Text, IsCustomerNumber = 1 });
                        }
                    }
                }
                else
                {
                    dtCustomer = new DataTable();
                    if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                    {
                        dtCustomer = new BALCustomerMaster().Search(new BOLCustomerMaster() { SalesRepID = 0, CustomerName = txtCustomerSearch.Text, IsCustomerNumber = 0 });
                    }
                    else
                    {
                        if (ViewAll == true)
                        {
                            dtCustomer = new BALCustomerMaster().Search(new BOLCustomerMaster() { SalesRepID = 0, CustomerName = txtCustomerSearch.Text, IsCustomerNumber = 0 });
                        }
                        else
                        {
                            dtCustomer = new BALCustomerMaster().Search(new BOLCustomerMaster() { SalesRepID = ClsCommon.UserID, CustomerName = txtCustomerSearch.Text, IsCustomerNumber = 0 });
                        }
                    }
                }
                if (dtCustomer.Rows.Count > 0)
                {

                    int j = 0;
                    dgvCustomerList.Rows.Clear();
                    for (int i = 0; i < dtCustomer.Rows.Count; i++)
                    {
                        dgvCustomerList.Rows.Add();
                        dgvCustomerList.Rows[j].Cells[0].Value = dtCustomer.Rows[i]["ID"].ToString();
                        dgvCustomerList.Rows[j].Cells[1].Value = "";
                        dgvCustomerList.Rows[j].Cells[2].Value = dtCustomer.Rows[i]["Customer"].ToString();
                        if (dtCustomer.Rows[i]["BalanceTotal"].ToString() != null || dtCustomer.Rows[i]["BalanceTotal"].ToString() != "")
                            dgvCustomerList.Rows[j].Cells[3].Value = dtCustomer.Rows[i]["BalanceTotal"].ToString();
                        else
                            dgvCustomerList.Rows[j].Cells[3].Value = "0.00";
                        if (ClsCommon.UserType != "Admin" && ClsCommon.UserType != "admin")
                        {
                            if (dtCustomer.Rows[i]["SalesRepID"].ToString() == null || dtCustomer.Rows[i]["SalesRepID"].ToString() == "" || dtCustomer.Rows[i]["SalesRepID"].ToString() == "0")
                                dgvCustomerList.Rows[i].DefaultCellStyle.BackColor = Color.Silver;
                        }
                        j++;
                    }
                }
                else
                {
                    MessageBox.Show("There are no results that meet this criteria.", "Empty List", MessageBoxButtons.OK);
                }

                lblTotal.Text = dgvCustomerList.Rows.Count.ToString();

            }
            catch (Exception ex)
            {
                ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter,Function :CustomerSearch. Message:" + ex.Message);
                MessageBox.Show("Error:" + ex.Message);
            }
        }
