        public void DisplayNoteForCustomer(int ID)
        {
            try
            {
                if (dgvCustomerList.Rows.Count > 0)
                {
                    dgNotes.Rows.Clear();

                    DataTable dt = ObjNoteBAL.SelectByCusID(ID);
                    if (dt.Rows.Count > 0)
                    {

                        int iRow = 0;
                        foreach (DataRow item in dt.Rows)
                        {
                            dgNotes.Rows.Add();
                            dgNotes[0, iRow].Value = item["ID"].ToString();
                            dgNotes[1, iRow].Value = item["Note"].ToString();
                            iRow++;
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter,Function :DisplayNoteForCustomer. Message:" + ex.Message);
                MessageBox.Show("Error:" + ex.Message);
            }

        }
        public void DisplayLog(string ID)
        {
            try
            {
                dgUser.Rows.Clear();
                DataTable dt = ObjCusBAL.SelectByCusID(Convert.ToInt32(ID));
                if (dt.Rows.Count > 0)
                {
                    int iRow = 0;
                    foreach (DataRow item in dt.Rows)
                    {
                        dgUser.Rows.Add();
                        dgUser[0, iRow].Value = item["ID"].ToString();
                        dgUser[1, iRow].Value = item["CreatedDate"].ToString();
                        dgUser[2, iRow].Value = item["LogName"].ToString();
                        iRow++;
                    }
                }

            }
            catch (Exception ex)
            {
                ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter,Function :DisplayLog. Message:" + ex.Message);
                MessageBox.Show("Error:" + ex.Message);
            }
        }
