        //Load Customer Data and Invoice load
        public void LoadCustomerData(Int32 CustomerID)
        {
            try
            {
                if (ClsCommon.FunctionVisibility("CustomerNumberOnly", "CustomerCenter"))
                {
                    if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                    {
                        CustomerNumberOnly = false;
                    }
                    else
                    {
                        CustomerNumberOnly = true;

                    }
                }
                else
                {
                    CustomerNumberOnly = false;
                }


                Boolean CustomerData = true;
                if (ClsCommon.FunctionVisibility("NotShowCustomerDetails", "CustomerCenter"))
                {
                    if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                    {
                        CustomerData = true;
                    }
                    else
                    {
                        CustomerData = false;
                    }
                }
                else
                {
                    CustomerData = true;
                }
                if (CustomerData == true)
                {
                    DataTable dt = new BALCustomerMaster().SelectByID(new BOLCustomerMaster() { ID = CustomerID });
                    if (dt.Rows.Count > 0)
                    {
                        BillAddress = "";

                        if (CustomerNumberOnly == true)
                        {
                            lblFullName.Text = dt.Rows[0]["CustomerNumber"].ToString();
                        }
                        else
                        {
                            lblFullName.Text = dt.Rows[0]["FullName"].ToString();
                        }
                        lblCompanyName.Text = dt.Rows[0]["CompanyName"].ToString();
                        lblTerms.Text = dt.Rows[0]["TermsName"].ToString();
                        if (dt.Rows[0]["Address1"].ToString() != "")
                            BillAddress = dt.Rows[0]["Address1"].ToString();
                        if (dt.Rows[0]["Address2"].ToString() != "")
                            BillAddress = BillAddress + "^" + dt.Rows[0]["Address2"].ToString();
                        if (dt.Rows[0]["Address3"].ToString() != "")
                            BillAddress = BillAddress + "^" + dt.Rows[0]["Address3"].ToString();
                        if (dt.Rows[0]["City"].ToString() != "")
                            BillAddress = BillAddress + "^" + dt.Rows[0]["City"].ToString();
                        if (dt.Rows[0]["State"].ToString() != "")
                            BillAddress = BillAddress + "^" + dt.Rows[0]["State"].ToString();
                        if (dt.Rows[0]["PostalCode"].ToString() != "")
                            BillAddress = BillAddress + "^" + dt.Rows[0]["PostalCode"].ToString();
                        //BillAddress.Replace(",,", ",");

                        lblAddress1.Text = "";
                        lblAddress2.Text = "";
                        lblAddress3.Text = "";
                        lblCityState.Text = "";
                        lblZipCode.Text = "";

                        string[] str = BillAddress.ToString().Split('^');
                        if (str.Length == 1)
                            lblAddress1.Text = str[0].ToString();
                        else if (str.Length == 2)
                        {
                            lblAddress1.Text = str[0].ToString();
                            lblAddress2.Text = str[1].ToString();
                        }
                        else if (str.Length == 3)
                        {
                            lblAddress1.Text = str[0].ToString();
                            lblAddress2.Text = str[1].ToString();
                            lblAddress3.Text = str[2].ToString();
                        }
                        else if (str.Length == 4)
                        {
                            lblAddress1.Text = str[0].ToString();
                            lblAddress2.Text = str[1].ToString();
                            lblAddress3.Text = str[2].ToString();
                            lblCityState.Text = str[3].ToString();
                        }
                        else if (str.Length == 5)
                        {
                            lblAddress1.Text = str[0].ToString();
                            lblAddress2.Text = str[1].ToString();
                            lblAddress3.Text = str[2].ToString();
                            lblCityState.Text = str[3].ToString() + "," + str[4].ToString();
                        }
                        else if (str.Length == 6)
                        {
                            lblAddress1.Text = str[0].ToString();
                            lblAddress2.Text = str[1].ToString();
                            lblAddress3.Text = str[2].ToString();
                            lblCityState.Text = str[3].ToString() + "," + str[4].ToString();
                            lblZipCode.Text = str[5].ToString();
                        }
                        lblMainPhone.Text = dt.Rows[0]["Phone"].ToString();
                        lblWorkPhone.Text = dt.Rows[0]["WorkPhone"].ToString();
                        lblMobile.Text = dt.Rows[0]["Mobile"].ToString();
                        lblFax.Text = dt.Rows[0]["Fax"].ToString();
                        lblMainEmail.Text = dt.Rows[0]["Email"].ToString();
                        lblCcEmail.Text = dt.Rows[0]["CcEmail"].ToString();
                        lblWebsite.Text = dt.Rows[0]["Website"].ToString();
                        lblOther.Text = dt.Rows[0]["Other"].ToString();
                    }
                }
                else
                {
                    lblCompanyName.Text = "";
                    lblFullName.Text = "";
                    lblTerms.Text = "";
                    lblAddress1.Text = "";
                    lblAddress2.Text = "";
                    lblAddress3.Text = "";
                    lblCityState.Text = "";
                    lblZipCode.Text = "";
                    lblAddress1.Text = "";
                    lblAddress2.Text = "";
                    lblAddress3.Text = "";
                    lblCityState.Text = "";
                    lblZipCode.Text = "";
                    lblMainPhone.Text = "";
                    lblWorkPhone.Text = "";
                    lblMobile.Text = "";
                    lblFax.Text = "";
                    lblMainEmail.Text = "";
                    lblCcEmail.Text = "";
                    lblWebsite.Text = "";
                    lblOther.Text = "";
                }

                // CustomerWise Invoice Load
                if (x == true)
                {
                    cmbTransactionsFilterDate.SelectedIndex = 0;
                    cmbFilterInvoice.SelectedIndex = 0;
                }
                CustomerWiseInvoiceLoad(CustomerID);

                // CustomerWise Pending Invoice Load
                cmbPendingInvoicedate.SelectedIndex = 0;
                cmbPendingInvoiceFilter.SelectedIndex = 0;
                CustomerWisePandingInvoices(CustomerID);
                DisplayNoteForCustomer(Convert.ToInt32(CustomerID));
                DisplayLog(CustomerID.ToString());
            }
            catch (Exception ex)
            {
                ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter, Function :LoadCustomerData. Message:" + ex.Message);
                MessageBox.Show("Error:" + ex.Message);
            }
        }
