        //CustomerTab selection Change
        private void tabCustomer_SelectedIndexChanged(object sender, EventArgs e)
        {
            try
            {
                if (tabCustomer.SelectedTab == this.tabInvoice)
                {
                    pnlAll.Controls.Remove(splitContainerHorizontal);
                    pnlAll.Controls.Add(PnlInvoiceList);
                    pnlMenuAll.Controls.Remove(pnlCustomerMenu);
                    pnlMenuAll.Controls.Add(pnlTransactionMenu);
                    PnlInvoiceList.Visible = true;
                    pnlTransactionMenu.Visible = true;
                    txtSearch.Text = "";
                    cmbInvoiceFilter.SelectedIndex = 0;
                    cmbInvoiceDate.SelectedIndex = 0;
                    cmbInvoiceTransactions.SelectedIndex = 0;
                    //cmbInvoiceRunReport.SelectedIndex = 0;
                    btnInvoices.Focus();
                    LoadFunction();
                    InvoiceType = "AllInvoice";
                    LoadAllInvoices();
                    IsCreditMemo = false;
                    timer1.Enabled = true;
                    //Hiren
                    cmbPayMethod.Visible = false;
                    label9.Visible = false;
                    cmbInvoiceFilter.Visible = true;
                    label1.Visible = true;
                    IsReceivePayment = false;
                }
                else if (tabCustomer.SelectedTab == this.tabCustomerandJobs)
                {
                    pnlAll.Controls.Remove(PnlInvoiceList);
                    pnlAll.Controls.Add(splitContainerHorizontal);
                    pnlMenuAll.Controls.Add(pnlCustomerMenu);
                    pnlMenuAll.Controls.Remove(pnlTransactionMenu);
                    PnlInvoiceList.Visible = false;
                    pnlTransactionMenu.Visible = false;
                    cmbFilterInvoice.SelectedIndex = 0;
                    cmbTransactionsFilterDate.SelectedIndex = 0;
                    cmbInvoiceManageTransactions.SelectedIndex = 0;
                    //cmbRunReport.SelectedIndex = 0;
                    cmbPendingInvoiceFilter.SelectedIndex = 0;
                    cmbPendingInvoicedate.SelectedIndex = 0;
                    cmbCustomerType.SelectedIndex = 0;
                    //LoadFunction();
                    LoadCustomer();
                    if (dgvCustomerList.CurrentRow != null)
                        CustRowIndex = dgvCustomerList.CurrentRow.Index;
                    timer1.Enabled = false;
                }
            }
            catch (Exception ex)
            {
                ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter,Function :tabCustomer_SelectedIndexChanged. Message:" + ex.Message);
                MessageBox.Show("Error:" + ex.Message);
            }

        }
