        private void CusInvoiceExport(ref DataTable dtInv)
        {
            try
            {
                DataTable dtTra = new DataTable();
                dtTra.Columns.Add("Total", typeof(string));
                dtTra.Columns.Add("Num", typeof(string));
                dtTra.Columns.Add("Date", typeof(string));
                dtTra.Columns.Add("Due Date", typeof(string));
                dtTra.Columns.Add("Amount", typeof(decimal));
                dtTra.Columns.Add("Open Balance", typeof(decimal));

                if (dtInv.Rows.Count > 0)
                {
                    Total = 0; TotalBalance = 0;
                    for (int i = 0; i < dtInv.Rows.Count; i++)
                    {
                        DataRow dr = dtTra.NewRow();
                        dr["Total"] = "";
                        dr["Num"] = dtInv.Rows[i]["Num"].ToString();
                        dr["Date"] = Convert.ToDateTime(dtInv.Rows[i]["Date"].ToString()).ToString("MM-dd-yyyy");
                        dr["Due Date"] = Convert.ToDateTime(dtInv.Rows[i]["DueDate"].ToString()).ToString("MM-dd-yyyy");
                        dr["Amount"] = dtInv.Rows[i]["Amount"].ToString();
                        dr["Open Balance"] = dtInv.Rows[i]["TotalBalance"].ToString();
                        Total += Convert.ToDecimal(dtInv.Rows[i]["Amount"].ToString());
                        TotalBalance += Convert.ToDecimal(dtInv.Rows[i]["TotalBalance"].ToString());
                        dtTra.Rows.Add(dr);
                    }

                    DataRow dr1 = dtTra.NewRow();
                    dr1["Total"] = "Total";
                    dr1["Amount"] = Total;
                    dr1["Open Balance"] = TotalBalance;
                    dtTra.Rows.Add(dr1);

                    SaveFileDialog sfd = new SaveFileDialog();
                    sfd.Filter = "Excel files (*.xlsx)|*.xlsx|All files (*.*)|*.*";
                    sfd.FilterIndex = 1;
                    sfd.RestoreDirectory = true;
                    sfd.InitialDirectory = Environment.GetFolderPath(Environment.SpecialFolder.Personal);
                    if (sfd.ShowDialog() == DialogResult.OK)
                    {
                        Cursor.Current = Cursors.WaitCursor;
                        string NewFileName = sfd.FileName;
                        int n = dtTra.Columns.Count;
                        string[] strArr = new string[n];
                        object objValue = System.Reflection.Missing.Value;
                        Excel.Application sXLApp = new Excel.Application();
                        Excel.Workbooks sXLBooks = (Excel.Workbooks)sXLApp.Workbooks;
                        Excel._Workbook sXLBook = (Excel._Workbook)(sXLBooks.Add(objValue));
                        Excel.Sheets sXLSheets = (Excel.Sheets)sXLBook.Worksheets;
                        Excel._Worksheet sXLWorksheet = (Excel._Worksheet)(sXLSheets.get_Item(1));

                        int p = 0;
                        for (int x = 0; x < n; x++)
                        {
                            if (p == 0)
                                strArr[x] = "";
                            else
                                strArr[x] = dtTra.Columns[p].ColumnName.ToString().Trim();
                            p++;
                        }
                        object objHeaders = (object)strArr;
                        Excel.Range sXLRange = sXLWorksheet.get_Range("A1", "IV1");
                        sXLRange.set_Value(objValue, objHeaders);
                        Excel.Font sXLFont = sXLRange.Font;

                        // To Assign Empty Column Header is null
                        for (int y = n + 1; y <= sXLRange.Count; y++)
                        {
                            sXLRange[1, y] = null;
                        }
                        sXLFont.Bold = true;

                        object[,] objData = new object[dtTra.Rows.Count, dtTra.Columns.Count];

                        for (int nRow = 0; nRow < dtTra.Rows.Count; nRow++)
                        {
                            for (int nCol = 0; nCol < dtTra.Columns.Count; nCol++)
                            {
                                objData[nRow, nCol] = dtTra.Rows[nRow][nCol].ToString().Trim();
                            }
                        }

                        sXLRange = sXLWorksheet.get_Range("A3", objValue);
                        sXLRange = sXLRange.get_Resize(dtTra.Rows.Count, dtTra.Columns.Count);
                        sXLRange.set_Value(objValue, objData);

                        Excel.Range BorderRAnge1;
                        BorderRAnge1 = sXLWorksheet.get_Range("B1", "F1");
                        BorderRAnge1.Font.Bold = true;
                        BorderRAnge1.BorderAround(Excel.XlLineStyle.xlContinuous, Excel.XlBorderWeight.xlMedium, Excel.XlColorIndex.xlColorIndexAutomatic, Excel.XlColorIndex.xlColorIndexAutomatic);
                        for (int nRow = 0; nRow < dtTra.Rows.Count; nRow++)
                        {
                            if (nRow == dtTra.Rows.Count - 1)
                            {
                                Excel.Range BorderRAnge2;
                                BorderRAnge2 = sXLWorksheet.get_Range("A" + Convert.ToInt32(dtTra.Rows.Count + 2), "F" + Convert.ToInt32(dtTra.Rows.Count + 2));
                                BorderRAnge2.Font.Bold = true;
                            }
                        }

                        //If you need Apply the color into Excel Cell based on Grid Cell     
                        for (int c = 1; c < dtTra.Columns.Count; c++)
                        {
                            // To get the Excel Cell Name     
                            string sCell = GetExcelCell(c + 1);

                            for (int r = 0; r < dtTra.Rows.Count; r++)
                            {
                                sXLRange = sXLWorksheet.get_Range(sCell + (r + 2), sCell + (r + 2));
                            }
                        }

                        sXLApp.Columns.EntireColumn.AutoFit();
                        sXLApp.Columns.EntireRow.AutoFit();

                        sXLBook.SaveAs(NewFileName, objValue, objValue, objValue, objValue, objValue,
                                            Excel.XlSaveAsAccessMode.xlNoChange, objValue, objValue, objValue, objValue, objValue);
                        sXLBook.Close(false, objValue, objValue);
                        sXLApp.Quit();
                        Cursor.Current = Cursors.Default;
                        MessageBox.Show("Export Successfully");
                        var app = new Microsoft.Office.Interop.Excel.Application();
                        app.Visible = true;
                        app.Workbooks.Open(sfd.FileName, ReadOnly: false);
                    }
                }
                else
                    MessageBox.Show("No Record Found");
            }
            catch (Exception ex)
            {
                ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter,Function :CusInvoiceExport. Message:" + ex.Message);
                MessageBox.Show("Error:" + ex.Message);
            }
        }
        //Customer Delete
        private void btnCustomerDelete_Click(object sender, EventArgs e)
        {
            try
            {
                if (ClsCommon.FunctionVisibility("CusDelete", "CustomerCenter"))
                {
                    DataTable dtInv = new BALInvoiceMaster().SelectByCusID(new BOLInvoiceMaster() { CustomerID = Convert.ToInt32(dgvCustomerList.CurrentRow.Cells["ID"].Value.ToString()) });
                    if (dtInv.Rows.Count == 0)
                    {
                        DialogResult result = MessageBox.Show("Are you sure to delete this record?", "Confirmation", MessageBoxButtons.YesNo);
                        if (result == DialogResult.Yes)
                        {
                            DataTable dtParent = new BALCustomerMaster().SelectByParentID(new BOLCustomerMaster() { ParentID = Convert.ToInt32(dgvCustomerList.CurrentRow.Cells["ID"].Value.ToString()) });
                            if (dtParent.Rows.Count > 0)
                            {
                                MessageBox.Show("You can delete an Customer that has SubCustomer.Delete or move the SubCustomer first.", "Warning");
                            }
                            else
                            {
                                ObjCustomerBOL.ID = Convert.ToInt32(dgvCustomerList.CurrentRow.Cells["ID"].Value.ToString());
                                ObjCustomerBAL.Delete(ObjCustomerBOL);
                                ObjNoteBAL.DeleteCusID(Convert.ToInt32(dgvCustomerList.CurrentRow.Cells["ID"].Value.ToString()));
                                MessageBox.Show("Record delete successfully");
                                cmbCustomerType.SelectedIndex = 1;
                                LoadCustomer();
                            }
                        }
                    }
                    else
                    {
                        MessageBox.Show("You cannot delete this name because its has a balance or " +
                            "it used in a Transactions.", "Warning");
                    }
                }
                else
                    MessageBox.Show("You can not access");
            }
            catch (Exception ex)
            {
                ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter,Function :btnCustomerDelete_Click. Message:" + ex.Message);
                MessageBox.Show("Error:" + ex.Message);
            }
        }
