        public void CustomerWisePandingInvoices(Int32 CusID)
        {
            try
            {
                Cursor.Current = Cursors.WaitCursor;
                lblPenFrom.Visible = false; lblPenTo.Visible = false; dtPenFrom.Visible = false; dtPenTo.Visible = false;
                //All Invoices

                if (cmbPendingInvoiceFilter.SelectedIndex == 0 && cmbPendingInvoicedate.SelectedIndex == 0)
                {
                    dtCusPendingInvoice = new DataTable();
                    if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                        dtCusPendingInvoice = new BALInvoiceMaster().SelectByCustomerWisePendingInvoice(new BOLInvoiceMaster() { CustomerID = CusID, StartDate = DateTime.Now.ToString("yyyy-MM-dd"), EndDate = DateTime.Now.ToString("yyyy-MM-dd"), CreatedID = 0 });
                    else
                        dtCusPendingInvoice = new BALInvoiceMaster().SelectByCustomerWisePendingInvoice(new BOLInvoiceMaster() { CustomerID = CusID, StartDate = DateTime.Now.ToString("yyyy-MM-dd"), EndDate = DateTime.Now.ToString("yyyy-MM-dd"), CreatedID = ClsCommon.UserID });
                }
                else if (cmbPendingInvoiceFilter.SelectedIndex == 0 && cmbPendingInvoicedate.SelectedIndex == 1)
                {
                    dtCusPendingInvoice = new DataTable();
                    DateTime dt = DateTime.Now.StartOfWeek(DayOfWeek.Sunday);
                    DateTime dt1 = dt.AddDays(6);
                    if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                        dtCusPendingInvoice = new BALInvoiceMaster().SelectByCustomerWisePendingInvoice(new BOLInvoiceMaster() { CustomerID = Convert.ToInt32(dgvCustomerList.CurrentRow.Cells["ID"].Value.ToString()), StartDate = dt.ToString("yyyy-MM-dd"), EndDate = dt1.ToString("yyyy-MM-dd"), CreatedID = 0 });
                    else
                        dtCusPendingInvoice = new BALInvoiceMaster().SelectByCustomerWisePendingInvoice(new BOLInvoiceMaster() { CustomerID = Convert.ToInt32(dgvCustomerList.CurrentRow.Cells["ID"].Value.ToString()), StartDate = dt.ToString("yyyy-MM-dd"), EndDate = dt1.ToString("yyyy-MM-dd"), CreatedID = ClsCommon.UserID });
                }
                else if (cmbPendingInvoiceFilter.SelectedIndex == 0 && cmbPendingInvoicedate.SelectedIndex == 2)
                {
                    dtCusPendingInvoice = new DataTable();
                    DateTime dt = DateTime.Now;
                    DateTime dt1 = Convert.ToDateTime(dt.Year + "-" + dt.Month + "-" + "01");
                    if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                        dtCusPendingInvoice = new BALInvoiceMaster().SelectByCustomerWisePendingInvoice(new BOLInvoiceMaster() { CustomerID = Convert.ToInt32(dgvCustomerList.CurrentRow.Cells["ID"].Value.ToString()), StartDate = dt1.ToString("yyyy-MM-dd"), EndDate = dt1.AddMonths(1).AddDays(-1).ToString("yyyy-MM-dd"), CreatedID = 0 });
                    else
                        dtCusPendingInvoice = new BALInvoiceMaster().SelectByCustomerWisePendingInvoice(new BOLInvoiceMaster() { CustomerID = Convert.ToInt32(dgvCustomerList.CurrentRow.Cells["ID"].Value.ToString()), StartDate = dt1.ToString("yyyy-MM-dd"), EndDate = dt1.AddMonths(1).AddDays(-1).ToString("yyyy-MM-dd"), CreatedID = ClsCommon.UserID });
                }
                else if (cmbPendingInvoiceFilter.SelectedIndex == 0 && cmbPendingInvoicedate.SelectedIndex == 3)
                {
                    dtCusPendingInvoice = new DataTable();
                    int year = DateTime.Now.Year;
                    DateTime firstDay = Convert.ToDateTime(year + "-" + "01" + "-" + "01");
                    if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                        dtCusPendingInvoice = new BALInvoiceMaster().SelectByCustomerWisePendingInvoice(new BOLInvoiceMaster() { CustomerID = Convert.ToInt32(dgvCustomerList.CurrentRow.Cells["ID"].Value.ToString()), StartDate = firstDay.ToString("yyyy-MM-dd"), EndDate = firstDay.AddYears(1).AddDays(-1).ToString("yyyy-MM-dd"), CreatedID = 0 });
                    else
                        dtCusPendingInvoice = new BALInvoiceMaster().SelectByCustomerWisePendingInvoice(new BOLInvoiceMaster() { CustomerID = Convert.ToInt32(dgvCustomerList.CurrentRow.Cells["ID"].Value.ToString()), StartDate = firstDay.ToString("yyyy-MM-dd"), EndDate = firstDay.AddYears(1).AddDays(-1).ToString("yyyy-MM-dd"), CreatedID = ClsCommon.UserID });
                }
                else if (cmbPendingInvoiceFilter.SelectedIndex == 0 && cmbPendingInvoicedate.SelectedIndex == 4)
                {
                    dtCusPendingInvoice = new DataTable();
                    DateTime dt = DateTime.Now.AddDays(-6).StartOfWeek(DayOfWeek.Sunday);
                    DateTime dt1 = dt.AddDays(6);
                    if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                        dtCusPendingInvoice = new BALInvoiceMaster().SelectByCustomerWisePendingInvoice(new BOLInvoiceMaster() { CustomerID = Convert.ToInt32(dgvCustomerList.CurrentRow.Cells["ID"].Value.ToString()), StartDate = dt.ToString("yyyy-MM-dd"), EndDate = dt1.ToString("yyyy-MM-dd"), CreatedID = 0 });
                    else
                        dtCusPendingInvoice = new BALInvoiceMaster().SelectByCustomerWisePendingInvoice(new BOLInvoiceMaster() { CustomerID = Convert.ToInt32(dgvCustomerList.CurrentRow.Cells["ID"].Value.ToString()), StartDate = dt.ToString("yyyy-MM-dd"), EndDate = dt1.ToString("yyyy-MM-dd"), CreatedID = ClsCommon.UserID });

                }
                else if (cmbPendingInvoiceFilter.SelectedIndex == 0 && cmbPendingInvoicedate.SelectedIndex == 5)
                {
                    dtCusPendingInvoice = new DataTable();
                    DateTime dt = DateTime.Now.AddMonths(-1);
                    DateTime dt1 = Convert.ToDateTime(dt.Year + "-" + dt.Month + "-" + "01");
                    if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                        dtCusPendingInvoice = new BALInvoiceMaster().SelectByCustomerWisePendingInvoice(new BOLInvoiceMaster() { CustomerID = Convert.ToInt32(dgvCustomerList.CurrentRow.Cells["ID"].Value.ToString()), StartDate = dt1.ToString("yyyy-MM-dd"), EndDate = dt1.AddMonths(1).AddDays(-1).ToString("yyyy-MM-dd"), CreatedID = 0 });
                    else
                        dtCusPendingInvoice = new BALInvoiceMaster().SelectByCustomerWisePendingInvoice(new BOLInvoiceMaster() { CustomerID = Convert.ToInt32(dgvCustomerList.CurrentRow.Cells["ID"].Value.ToString()), StartDate = dt1.ToString("yyyy-MM-dd"), EndDate = dt1.AddMonths(1).AddDays(-1).ToString("yyyy-MM-dd"), CreatedID = ClsCommon.UserID });
                }
                else if (cmbPendingInvoiceFilter.SelectedIndex == 0 && cmbPendingInvoicedate.SelectedIndex == 6)
                {
                    dtCusPendingInvoice = new DataTable();
                    int year = DateTime.Now.Year;
                    DateTime firstDay = Convert.ToDateTime(year + "-" + "01" + "-" + "01").AddYears(-1);
                    if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                        dtCusPendingInvoice = new BALInvoiceMaster().SelectByCustomerWisePendingInvoice(new BOLInvoiceMaster() { CustomerID = Convert.ToInt32(dgvCustomerList.CurrentRow.Cells["ID"].Value.ToString()), StartDate = firstDay.ToString("yyyy-MM-dd"), EndDate = firstDay.AddYears(1).AddDays(-1).ToString("yyyy-MM-dd"), CreatedID = 0 });
                    else
                        dtCusPendingInvoice = new BALInvoiceMaster().SelectByCustomerWisePendingInvoice(new BOLInvoiceMaster() { CustomerID = Convert.ToInt32(dgvCustomerList.CurrentRow.Cells["ID"].Value.ToString()), StartDate = firstDay.ToString("yyyy-MM-dd"), EndDate = firstDay.AddYears(1).AddDays(-1).ToString("yyyy-MM-dd"), CreatedID = ClsCommon.UserID });
                }
                else if (cmbPendingInvoiceFilter.SelectedIndex == 0 && cmbPendingInvoicedate.SelectedIndex == 7)
                {
                    dtCusPendingInvoice = new DataTable();
                    lblPenFrom.Visible = true; lblPenTo.Visible = true; dtPenFrom.Visible = true; dtPenTo.Visible = true;
                }

                else if (cmbPendingInvoiceFilter.SelectedIndex == 1 && cmbPendingInvoicedate.SelectedIndex == 0)
                {
                    dtCusPendingInvoice = new DataTable();
                    if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
