                {
                    int j = 0; decimal Total = 0;
                    dgvPendingInvoice.Rows.Clear();
                    for (int i = 0; i < dtCusPendingInvoice.Rows.Count; i++)
                    {
                        dgvPendingInvoice.Rows.Add();
                        dgvPendingInvoice.Rows[j].Cells[0].Value = dtCusPendingInvoice.Rows[i]["ID"].ToString();
                        dgvPendingInvoice.Rows[j].Cells[1].Value = "Invoice";
                        dgvPendingInvoice.Rows[j].Cells[2].Value = dtCusPendingInvoice.Rows[i]["Num"].ToString();
                        dgvPendingInvoice.Rows[j].Cells[3].Value = Convert.ToDateTime(dtCusPendingInvoice.Rows[i]["Date"].ToString()).ToString("MM-dd-yyyy"); ;
                        dgvPendingInvoice.Rows[j].Cells[4].Value = dtCusPendingInvoice.Rows[i]["AccountName"].ToString();
                        dgvPendingInvoice.Rows[j].Cells[5].Value = dtCusPendingInvoice.Rows[i]["Terms"].ToString();
                        dgvPendingInvoice.Rows[j].Cells[6].Value = dtCusPendingInvoice.Rows[i]["SalesRep"].ToString();

                        if (dtCusPendingInvoice.Rows[i]["PaidInvoice"].ToString() == "0")
                        {
                            dgvPendingInvoice.Rows[j].Cells[7].Value = "Unpaid";
                        }
                        else if (dtCusPendingInvoice.Rows[i]["PaidInvoice"].ToString() == "1")
                        {
                            dgvPendingInvoice.Rows[j].Cells[7].Value = "Partially Paid";
                            dgvPendingInvoice.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#33B864");
                        }
                        else if (dtCusPendingInvoice.Rows[i]["PaidInvoice"].ToString() == "2")
                        {
                            dgvPendingInvoice.Rows[j].Cells[7].Value = "Paid";
                            dgvPendingInvoice.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#228B22");
                        }
                        dgvPendingInvoice.Rows[j].Cells[8].Value = dtCusPendingInvoice.Rows[i]["Amount"].ToString();



                        int INVID = Convert.ToInt32(dtCusPendingInvoice.Rows[i]["ID"].ToString());
                        DataTable dt = BALHistory.Select(INVID);

                        if (dtCusPendingInvoice.Rows[i]["Amount"].ToString() != "")
                        {
                            Total += Convert.ToDecimal(dtCusPendingInvoice.Rows[i]["Amount"].ToString());
                        }

                        j++;
                    }
                    lblCusWisePenTotal.Text = Total.ToString("N2");
                }
                else
                {
                    dgvPendingInvoice.Rows.Clear();
                    lblCusWisePenTotal.Text = "0.00";
                }
                Cursor.Current = Cursors.Default;
            }
            catch (Exception ex)
            {
                Cursor.Current = Cursors.Default;
                ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter, Function :CustomerWisePandingInvoices. Message:" + ex.Message);
                MessageBox.Show("Error:" + ex.Message);
            }
        }
        // CustomerWise Panding Invoice Edit
        private void dgvPandingInvoice_CellContentDoubleClick(object sender, DataGridViewCellEventArgs e)
        {
            try
            {
                if (ClsCommon.FunctionVisibility("InvUpdate", "CustomerCenter"))
                {
                    ClsCommon.ObjInvoiceMaster.EditableField();
                    ClsCommon.TaxWithoutTax = "";
                    ClsCommon.ObjInvoiceMaster.Show();
                    ClsCommon.ObjInvoiceMaster.LoadData(dgvPendingInvoice.CurrentRow.Cells["PandingInvID"].Value.ToString());
                    ClsCommon.ObjInvoiceMaster.AllowLowestPrice();
                    //dgvCustomerList.Rows[CustRowIndex].Selected = true;
                    LoadCustomerData(Convert.ToInt16(dgvCustomerList.CurrentRow.Cells["ID"].Value.ToString()));
                }
                else
                    MessageBox.Show("You can not access");
            }
            catch (Exception ex)
            {
                ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter,Function :dgvPandingInvoice_CellContentDoubleClick. Message:" + ex.Message);
                MessageBox.Show("Error:" + ex.Message);
            }
        }
        private void btnSe_Click(object sender, EventArgs e)
        {
            try
            {

                if (txtSearch.Text != "")
                {
                    if (ClsCommon.FunctionVisibility("CustomerNumberOnly", "CustomerCenter"))
                    {
                        if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                        {
                            CustomerNumberOnly = false;
                        }
                        else
                        {
                            CustomerNumberOnly = true;

                        }
                    }
                    else
                    {
                        CustomerNumberOnly = false;
                    }
                    dtAllInvoice = new DataTable();
                    DataTable dtMergeData = new DataTable();
                    try
                    {
                        Cursor.Current = Cursors.WaitCursor;
                        if (InvoiceType == "AllInvoice" || InvoiceType == "Invoice&CreditMemo")
                        {
                            dtAllInvoice = new DataTable();
                            if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                                dtAllInvoice = new BALInvoiceMaster().SelectSearchInvoice(new BOLInvoiceMaster() { SalesRepID = 0, RefNumber = txtSearch.Text, CustomerName = txtSearch.Text, IsCustomerNumber = 0 });
                            else
                                dtAllInvoice = new BALInvoiceMaster().SelectSearchInvoice(new BOLInvoiceMaster() { SalesRepID = ClsCommon.UserID, RefNumber = txtSearch.Text, CustomerName = txtSearch.Text, IsCustomerNumber = 1 });
                            if (InvoiceType == "Invoice&CreditMemo")
                            {
                                dtMergeData = dtAllInvoice;
                                dtMergeData.Columns.Add("Type");
                                for (int i = 0; i < dtMergeData.Rows.Count; i++)
                                {
                                    dtMergeData.Rows[i]["Type"] = "Invoice";
                                }
                            }
                            else
                            {
                                dtAllInvoice.Columns.Add("Type");
                            }
                        }
                        if (InvoiceType == "CreditMemo" || InvoiceType == "Invoice&CreditMemo")
                        { //custom
                            if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                                dtAllInvoice = new BALCreditMemo().SelectSearchInvoice(new BOLCreditMemo() { SalesRepID = 0, RefNumber = txtSearch.Text, CustomerName = txtSearch.Text, IsCustomerNumber = 0 });
                            else
                                dtAllInvoice = new BALCreditMemo().SelectSearchInvoice(new BOLCreditMemo() { SalesRepID = ClsCommon.UserID, RefNumber = txtSearch.Text, CustomerName = txtSearch.Text, IsCustomerNumber = 1 });
                            dtAllInvoice.Columns.Add("Type");
                        }

                        if (InvoiceType == "Invoice&CreditMemo")
                        {
                            dtMergeData.Merge(dtAllInvoice);
                            for (int i = 0; i < dtMergeData.Rows.Count; i++)
                            {
                                if (dtMergeData.Rows[i]["Type"].ToString() == "")
                                {
                                    dtMergeData.Rows[i]["Type"] = "Credit Memo";
                                }
                            }
                            dtAllInvoice.Rows.Clear();
                            dtAllInvoice = dtMergeData;
                            dgvAllInvoiceList.Columns["TYPE1"].Visible = true;
                        }
                        //Hiren
                        if (InvoiceType == "ReceviePayment")
                        {
                            dtAllInvoice = new DataTable();
                            if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                                dtAllInvoice = new BALPaymentDetail().SelectSearchPayment(new BOLPaymentDetail() { SalesRepID = 0, RefNumber = txtSearch.Text, FullName = txtSearch.Text, IsCustomerNumber = 0, });
                            else
                                dtAllInvoice = new BALPaymentDetail().SelectSearchPayment(new BOLPaymentDetail() { SalesRepID = ClsCommon.UserID, RefNumber = txtSearch.Text, FullName = txtSearch.Text, IsCustomerNumber = 1 });
                            if (InvoiceType == "Invoice&CreditMemo")
                            {
                                dtMergeData = dtAllInvoice;
                                dtMergeData.Columns.Add("Type");
                                for (int i = 0; i < dtMergeData.Rows.Count; i++)
                                {
                                    dtMergeData.Rows[i]["Type"] = "Invoice";
                                }
                            }
                            else
                            {
                                dtAllInvoice.Columns.Add("Type");
                            }
                        }
                        else
                        {
                            dgvAllInvoiceList.Columns["TYPE1"].Visible = false;
                        }

                        try
                        {

                            if (dtAllInvoice.Rows.Count > 0)
                            {
                                int j = 0; decimal AmountTotal = 0; decimal OpenTotal = 0; decimal TotalProfit = 0;
                                dgvAllInvoiceList.ClearSelection();
                                dgvAllInvoiceList.ClearFilter();
                                dgvAllInvoiceList.DataSource = null;
                                dgvAllInvoiceList.Rows.Clear();
                                for (int i = 0; i < dtAllInvoice.Rows.Count; i++)
                                {
                                    try
                                    {
                                        if (InvoiceType == "ReceviePayment")
                                        {

                                            var customerIdObj = dtAllInvoice.Rows[i]["CustomerID"];
                                            string customerId = customerIdObj != DBNull.Value ? customerIdObj.ToString() : string.Empty;

                                            if (string.IsNullOrEmpty(customerId) || customerId == "0")
                                            {
                                                continue;
                                            }
                                        }
                                    }
                                    catch (Exception ex)
                                    {
                                        ClsCommon.WriteErrorLogs("Hiren Codes Message:- " + ex.Message + "Value:-" + dtAllInvoice.Rows[i]["CustomerID"]);
                                        MessageBox.Show("Hiren Codes Message:- " + ex.Message + "Value:-" + dtAllInvoice.Rows[i]["CustomerID"]);
                                    }
                                    dgvAllInvoiceList.Rows.Add();
                                    DataTable dtcustomer = new DataTable();
                                    if (InvoiceType == "Invoice&CreditMemo")
                                    {
                                        dgvAllInvoiceList.Rows[j].Cells["TYPE1"].Value = dtAllInvoice.Rows[i]["Type"].ToString();
                                    }
                                    else
                                    {
                                        dgvAllInvoiceList.Rows[j].Cells["TYPE1"].Value = "";
                                    }
                                    if (IsCreditMemo == false && (dtAllInvoice.Rows[i]["Type"].ToString() == "Invoice" || dtAllInvoice.Rows[i]["Type"].ToString() == ""))
                                    {
                                        if (dtAllInvoice.Rows[i]["Num"].ToString() != "")
                                        {
                                            dtshipping = BALFedEx.SelectByRefNo(dtAllInvoice.Rows[i]["Num"].ToString());
                                            if (dtshipping.Rows.Count > 0)
                                            {
                                                int LastRow = dtshipping.Rows.Count - 1;
                                                if (dtshipping.Rows[LastRow]["TotalCost"].ToString() != "")
                                                {
                                                    dgvAllInvoiceList.Rows[j].Cells["ShipCharges"].Value = "Shipped " + dtshipping.Rows[LastRow]["TotalCost"].ToString();
                                                }
                                                else
                                                {
                                                    dgvAllInvoiceList.Rows[j].Cells["ShipCharges"].Value = "Shipped";
                                                }
                                                //dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = Color.Brown;
                                                dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#b7a591");
                                                dgvAllInvoiceList.Rows[j].Cells["ShipStatus"].Value = "SHIPPED";
                                            }
                                            else
                                            {
                                                if (dtAllInvoice.Rows[i]["ShipStatus"].ToString() != "")
                                                {
                                                    dgvAllInvoiceList.Rows[j].Cells["ShipStatus"].Value = dtAllInvoice.Rows[i]["ShipStatus"].ToString();
                                                }
                                            }

                                        }
                                        DataTable dtInvoice = new BALInvoiceDetails().SelectByID(new BOLInvoiceDetails() { InvoiceID = Convert.ToInt32(dtAllInvoice.Rows[i]["ID"].ToString()) });
                                        if (dtInvoice.Rows.Count > 0)
                                        {
                                            DataRow[] drShipping = dtInvoice.Select("[ItemFullName]='shipping'");
                                            {
                                                if (IsCreditMemo == false && (dtAllInvoice.Rows[i]["Type"].ToString() == "Invoice" || dtAllInvoice.Rows[i]["Type"].ToString() == ""))
                                                {
                                                    if (drShipping.Length > 0)
                                                    {
                                                        DataTable dtShipping = drShipping.CopyToDataTable();
                                                        dgvAllInvoiceList.Rows[j].Cells["ShippingCost"].Value = "$" + dtShipping.Rows[0]["Rate"].ToString();
                                                    }
                                                    else
                                                    {
                                                        dgvAllInvoiceList.Rows[j].Cells["ShippingCost"].Value = "$0.00";
                                                    }
                                                }
                                                else
                                                {
                                                    dgvAllInvoiceList.Rows[j].Cells["ShippingCost"].Value = "";
                                                }
                                            }
                                            DataRow[] drNote = dtInvoice.Select("[ItemFullName]='NOTES'");
                                            {
                                                if (drNote.Length > 0)
                                                {
                                                    dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = Color.SkyBlue;
                                                }
                                            }
                                        }
                                        decimal TotalDetails = 0;
                                        DataTable newDetails = new BALInvoiceDetails().SelectByInvID(new BOLInvoiceDetails() { InvoiceID = Convert.ToInt32(dtAllInvoice.Rows[i]["ID"].ToString()) });
                                        if (newDetails.Rows.Count > 0)
                                        {

                                            foreach (DataRow dr in newDetails.Rows)
                                            {
                                                if (dr["Cost"].ToString() == "")
                                                {
                                                    dr["Cost"] = 0.00;
                                                }
                                                if (dr["Cost"].ToString() != "0.00")
                                                {
                                                    TotalDetails += Convert.ToDecimal(dr["Quantity"].ToString()) * (Convert.ToDecimal(dr["Rate"].ToString()) - Convert.ToDecimal(dr["Cost"].ToString()));
                                                }
                                            }
                                        }
                                        dgvAllInvoiceList.Rows[j].Cells["Profit"].Value = string.Concat(decimal.Round(TotalDetails, 2));
                                        if (dtAllInvoice.Rows[i]["Amount"].ToString() != "0.00" && dtAllInvoice.Rows[i]["Amount"].ToString() != "")
                                        {
                                            dgvAllInvoiceList.Rows[j].Cells["ProfitPercentage"].Value = string.Concat(decimal.Round((Convert.ToDecimal(TotalDetails) / Convert.ToDecimal(dtAllInvoice.Rows[i]["Amount"].ToString())) * 100, 2), '%');
                                        }
                                        else
                                        {
                                            dgvAllInvoiceList.Rows[j].Cells["ProfitPercentage"].Value = "0%";
                                        }
                                        dtcustomer = new BALInvoiceMaster().SelectByCusID(new BOLInvoiceMaster() { CustomerID = Convert.ToInt32(dtAllInvoice.Rows[i]["CustomerID"].ToString()) });
                                        int Count = 0;
                                        Count = dtcustomer.Rows.Count;
                                        if (Count == 1)
                                        {
                                            dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#EF6262");
                                        }
                                        dgvAllInvoiceList.Rows[j].Cells["NoOfInvoice"].Value = Count;
                                        if (dtAllInvoice.Rows[i]["OpenBalance"].ToString() != "")
                                        {
                                            dgvAllInvoiceList.Rows[j].Cells["OpenBalance"].Value = Convert.ToDecimal(dtAllInvoice.Rows[i]["OpenBalance"].ToString());
                                        }
                                        DataTable dtInvoiceNumber = new BALInvoiceMaster().SelectByRefNumber(new BOLInvoiceMaster() { RefNumber = dtAllInvoice.Rows[i]["Num"].ToString() });
                                        if (dtInvoiceNumber.Rows.Count > 0)
                                        {
                                            dgvAllInvoiceList.Rows[j].Cells["VIA_Services"].Value = dtInvoiceNumber.Rows[0]["ShipmethodName"].ToString();
                                        }
                                        if (dtAllInvoice.Rows[i]["PandingInvoice"].ToString() == "0")
                                        {
                                            dgvAllInvoiceList.Rows[j].Cells["PendingInvoice"].Value = "Panding";
                                        }
                                        if (dtAllInvoice.Rows[i]["PaidInvoice"].ToString() == "0")
                                        {
                                            dgvAllInvoiceList.Rows[j].Cells["PaidStatus"].Value = "Unpaid";
                                        }
                                        else if (dtAllInvoice.Rows[i]["PaidInvoice"].ToString() == "1")
                                        {
                                            dgvAllInvoiceList.Rows[j].Cells["PaidStatus"].Value = "Partially Paid";
                                            dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#90EE90");
                                        }
                                        else if (dtAllInvoice.Rows[i]["PaidInvoice"].ToString() == "2")
                                        {
                                            dgvAllInvoiceList.Rows[j].Cells["PaidStatus"].Value = "Paid";
                                            dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#228B22");
                                        }
                                        if (dtAllInvoice.Rows[i]["Amount"].ToString() != "")
                                        {
                                            dgvAllInvoiceList.Rows[j].Cells["InvoiceAmount"].Value = Convert.ToDecimal(dtAllInvoice.Rows[i]["Amount"].ToString());
                                        }
                                        if (dtAllInvoice.Rows[i]["Amount"].ToString() != "")
                                        {
                                            AmountTotal += Convert.ToDecimal(dtAllInvoice.Rows[i]["Amount"].ToString());
                                        }
                                        if (dtAllInvoice.Rows[i]["OpenBalance"].ToString() != "")
                                        {
                                            OpenTotal += Convert.ToDecimal(dtAllInvoice.Rows[i]["OpenBalance"].ToString());
                                        }
                                        //if (dtAllInvoice.Rows[j].Cells["Profit"].Value != "")
                                        //{
                                        //    TotalProfit += Convert.ToDecimal(dtAllInvoice.Rows[j].Cells["Profit"].Value);
                                        //}


                                        if (TotalDetails != 0)
                                        {
                                            TotalProfit += decimal.Round(TotalDetails, 2);
                                        }

                                    }
                                    else
                                    {
                                        DataTable dtInvoice = new BALCreditMemoDetails().SelectByID(new BOLCreditMemoDetails() { InvoiceID = Convert.ToInt32(dtAllInvoice.Rows[i]["ID"].ToString()) });
                                        if (dtInvoice.Rows.Count > 0)
                                        {
                                            DataRow[] drNote = dtInvoice.Select("[ItemFullName]='NOTES'");
                                            {
                                                if (drNote.Length > 0)
                                                {
                                                    dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = Color.SkyBlue;
                                                }
                                            }
                                        }
                                        if (dtAllInvoice.Rows[i]["ShipStatus"].ToString() != "")
                                        {
                                            dgvAllInvoiceList.Rows[j].Cells["ShipStatus"].Value = dtAllInvoice.Rows[i]["ShipStatus"].ToString();
                                        }
                                        dgvAllInvoiceList.Rows[j].Cells["Profit"].Value = "";
                                        dgvAllInvoiceList.Rows[j].Cells["ProfitPercentage"].Value = "";
                                        dtcustomer = new BALCreditMemo().SelectByCusID(Convert.ToInt32(dtAllInvoice.Rows[i]["CustomerID"].ToString()));
                                        int Count = 0;
                                        Count = dtcustomer.Rows.Count;
                                        if (Count == 1)
                                        {
                                            dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#EF6262");
                                        }
                                        dgvAllInvoiceList.Rows[j].Cells["NoOfInvoice"].Value = Count;
                                        if (dtAllInvoice.Rows[i]["OpenBalance"].ToString() != "")
                                        {
                                            dgvAllInvoiceList.Rows[j].Cells["OpenBalance"].Value = Decimal.Negate(Convert.ToDecimal(dtAllInvoice.Rows[i]["OpenBalance"].ToString()));
                                        }
                                        DataTable dtInvoiceNumber = new BALCreditMemo().SelectByRefNumber(new BOLCreditMemo() { RefNumber = dtAllInvoice.Rows[i]["Num"].ToString() });
                                        if (dtInvoiceNumber.Rows.Count > 0)
                                        {
                                            dgvAllInvoiceList.Rows[j].Cells["VIA_Services"].Value = dtInvoiceNumber.Rows[0]["ShipmethodName"].ToString();
                                        }
                                        dgvAllInvoiceList.Rows[j].Cells["PendingInvoice"].Value = "";
                                        if (dtAllInvoice.Rows[i]["PaidInvoice"].ToString() == "0")
                                        {
                                            dgvAllInvoiceList.Rows[j].Cells["PaidStatus"].Value = "Unpaid";
                                        }
                                        else if (dtAllInvoice.Rows[i]["PaidInvoice"].ToString() == "1")
                                        {
                                            dgvAllInvoiceList.Rows[j].Cells["PaidStatus"].Value = "Partially Paid";
                                            dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#90EE90");
                                        }
                                        else if (dtAllInvoice.Rows[i]["PaidInvoice"].ToString() == "2")
                                        {
                                            dgvAllInvoiceList.Rows[j].Cells["PaidStatus"].Value = "Paid";
                                            dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#228B22");
                                        }

                                        if (dtAllInvoice.Rows[i]["Amount"].ToString() != "")
                                        {
                                            dgvAllInvoiceList.Rows[j].Cells["InvoiceAmount"].Value = Decimal.Negate(Convert.ToDecimal(dtAllInvoice.Rows[i]["Amount"].ToString()));
                                        }
                                        if (dtAllInvoice.Rows[i]["Amount"].ToString() != "")
                                        {
                                            AmountTotal += Decimal.Negate(Convert.ToDecimal(dtAllInvoice.Rows[i]["Amount"].ToString()));
                                        }
                                        if (dtAllInvoice.Rows[i]["OpenBalance"].ToString() != "")
                                        {
                                            OpenTotal += Decimal.Negate(Convert.ToDecimal(dtAllInvoice.Rows[i]["OpenBalance"].ToString()));
                                        }
                                        //dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#d60000");
                                        dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#F4C2C2");

                                    }
                                    if (InvoiceType != "ReceviePayment")
                                    {
                                        dgvAllInvoiceList.Rows[j].Cells["InvID"].Value = dtAllInvoice.Rows[i]["ID"].ToString();
                                    }
                                    else
                                    {
                                        dgvAllInvoiceList.Rows[j].Cells["InvID"].Value = dtAllInvoice.Rows[i]["InvoiceID"].ToString();
                                        dgvAllInvoiceList.Rows[j].Cells["PayID1"].Value = dtAllInvoice.Rows[i]["ID"].ToString();
                                    }
                                    //dgvAllInvoiceList.Rows[j].Cells["InvID"].Value = dtAllInvoice.Rows[i]["ID"].ToString();

                                    dgvAllInvoiceList.Rows[j].Cells["CustomerID"].Value = dtAllInvoice.Rows[i]["CustomerID"].ToString();
                                    if (CustomerNumberOnly == true)
                                    {
                                        dgvAllInvoiceList.Rows[j].Cells["CustomerNm"].Value = dtAllInvoice.Rows[i]["CustomerNumber"].ToString();
                                    }
                                    else
                                    {
                                        dgvAllInvoiceList.Rows[j].Cells["CustomerNm"].Value = dtAllInvoice.Rows[i]["Customer"].ToString();
                                    }

                                    //dgvAllInvoiceList.Rows[j].Cells["CustomerNm"].Value = dtAllInvoice.Rows[i]["Customer"].ToString();
                                    if (dtAllInvoice.Rows[i]["Num"].ToString() != "")
                                    {
                                        //dgvAllInvoiceList.Rows[j].Cells[4].Value = Convert.ToInt32(dtAllInvoice.Rows[i]["Num"].ToString());
                                        dgvAllInvoiceList.Rows[j].Cells["InvoiceNum"].Value = dtAllInvoice.Rows[i]["Num"].ToString();
                                    }
                                    if (dtAllInvoice.Rows[i]["CreatedTime"].ToString() != "")
                                    {
                                        DateTime date = Convert.ToDateTime(dtAllInvoice.Rows[i]["CreatedTime"].ToString());
                                        dgvAllInvoiceList.Rows[j].Cells["CREATEDATE"].Value = date;
                                        //}
                                        ////Nidhi
                                        //if (dtAllInvoice.Rows[i]["CreatedTime"].ToString() != "")
                                        //{
                                        dgvAllInvoiceList.Rows[j].Cells["CREATETIME"].Value = date.ToString("HH:mm:ss");
                                    }
                                    if (dtAllInvoice.Rows[i]["ModifiedTime"].ToString() != "")
                                    {
                                        DateTime date = Convert.ToDateTime(dtAllInvoice.Rows[i]["ModifiedTime"].ToString());
                                        dgvAllInvoiceList.Rows[j].Cells["InvoiceDate"].Value = date;
                                        //}
                                        ////Nidhi
                                        //if (dtAllInvoice.Rows[i]["CreatedTime"].ToString() != "")
                                        //{
                                        dgvAllInvoiceList.Rows[j].Cells["TIME"].Value = date.ToString("HH:mm:ss");
                                    }
                                    if (dtAllInvoice.Rows[i]["DueDate"].ToString() != "")
                                    {
                                        DateTime date = Convert.ToDateTime(dtAllInvoice.Rows[i]["DueDate"].ToString());
                                        dgvAllInvoiceList.Rows[j].Cells["DueDate"].Value = date;
                                    }
                                    dgvAllInvoiceList.Rows[j].Cells["Term"].Value = dtAllInvoice.Rows[i]["Terms"].ToString();

                                    if (InvoiceType != "ReceviePayment")
                                    {
                                        dgvAllInvoiceList.Rows[j].Cells["Rep"].Value = dtAllInvoice.Rows[i]["SalesRep"].ToString();
                                        dgvAllInvoiceList.Rows[j].Cells["CountEdit"].Value = dtAllInvoice.Rows[i]["InvoiceEdit"].ToString();

                                        if (dtAllInvoice.Rows[i]["ErrorLog"].ToString() != "")
                                        {
                                            dgvAllInvoiceList.Rows[j].Cells["Error"].Value = "ViewError";
                                        }
                                    }

                                    //Hiren
                                    try
                                    {
                                        //if (dtAllInvoice.Rows[i]["Num"].ToString().StartsWith("9000"))
                                        if (dtAllInvoice.Rows[i]["Num"].ToString().Contains("9000") == true)
                                        {
                                            dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#FF7F7F");
                                            dgvAllInvoiceList.Rows[j].DefaultCellStyle.ForeColor = System.Drawing.Color.Black;
                                        }
                                        else if (dtAllInvoice.Rows[i]["Num"].ToString().Contains("T") == true)
                                        {
                                            dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#FF7F7F");
                                            dgvAllInvoiceList.Rows[j].DefaultCellStyle.ForeColor = System.Drawing.Color.Black;
                                        }
                                    }
                                    catch (Exception ex)
                                    {
                                        ClsCommon.WriteErrorLogs("Hiren Codes for colour Message:- " + ex.Message + "Value:-" + dtAllInvoice.Rows[i]["Num"].ToString());
                                        MessageBox.Show("Hiren Codes for colour Message:- " + ex.Message + "Value:-" + dtAllInvoice.Rows[i]["Num"].ToString());
                                    }

                                    j++;
                                }
                                lblAmountTotal.Text = AmountTotal.ToString("N2");
                                lblOpenTotal.Text = OpenTotal.ToString("N2");
                                lblTotalProfitBalance.Text = TotalProfit.ToString("N2");
                                dgvAllInvoiceList.Sort(dgvAllInvoiceList.Columns["NoOfInvoice"], ListSortDirection.Ascending);

                            }
                            else
                            {
                                lblAmountTotal.Text = "0.00";
                                lblOpenTotal.Text = "0.00";
                                //txtTotalProfit.Text = "0.00";
                                lblTotalProfitBalance.Text = "0.00";
                                dgvAllInvoiceList.Rows.Clear();
                            }
                        }
                        catch (Exception ex)
                        {
                            ClsCommon.WriteErrorLogs("Serachbutton issuue");
                            MessageBox.Show("Serachbutton issuue");
                        }
                        Cursor.Current = Cursors.Default;
                    }
                    catch (Exception ex)
                    {
                        ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter,Function :dtTo_Leave. Message:" + ex.Message);
                        MessageBox.Show("Error:" + ex.Message);
                    }

                }
                else
                {
                    lblAmountTotal.Text = "0.00";
                    lblOpenTotal.Text = "0.00";
                    lblTotalProfitBalance.Text = "0.00";
                    dgvAllInvoiceList.Rows.Clear();
                }

            }
            catch (Exception ex)
            {
                ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter,Function :btnSearch_Click. Message:" + ex.Message);
                MessageBox.Show("Error:" + ex.Message);
            }
            dtFilter.Rows.Clear();
            if (SBind.DataSource == null)
            {
                foreach (DataGridViewColumn column in dgvAllInvoiceList.Columns)
                {
                    dtFilter.Columns.Add(column.HeaderText);
                }
            }
            foreach (DataGridViewRow row in dgvAllInvoiceList.Rows)
            {
                dtFilter.Rows.Add();
                foreach (DataGridViewCell cell in row.Cells)
                {
                    if (cell.Value != null)
                    {
                        dtFilter.Rows[dtFilter.Rows.Count - 1][cell.ColumnIndex] = cell.Value.ToString();
                    }
                    else if (cell.EditedFormattedValue != null)
                    {
                        if (cell.EditedFormattedValue.ToString().ToLower() != "false")
                            dtFilter.Rows[dtFilter.Rows.Count - 1][cell.ColumnIndex] = cell.EditedFormattedValue.ToString();
                    }
                }
            }
            SBind.DataSource = dtFilter;
        }
