        //Export Invoice Data
        private void btnInvExport_Click(object sender, EventArgs e)
        {
            try
            {

                if (ClsCommon.FunctionVisibility("InvExport", "CustomerCenter"))
                {
                    DataTable dt = new DataTable();
                    foreach (DataGridViewColumn column in dgvAllInvoiceList.Columns)
                    {
                        dt.Columns.Add(column.HeaderText);
                    }
                    foreach (DataGridViewRow row in dgvAllInvoiceList.Rows)
                    {
                        dt.Rows.Add();
                        foreach (DataGridViewCell cell in row.Cells)
                        {
                            if (cell.FormattedValue != null)
                            {
                                dt.Rows[dt.Rows.Count - 1][cell.ColumnIndex] = cell.FormattedValue.ToString();
                            }
                        }
                    }
                    //DataTable Dt1 = new DataTable();
                    //dt= dt.Select("DATE ASC").CopyToDataTable();
                    //dt.DefaultView.Sort = "DATE DESC";
                    DataView view = dt.DefaultView;
                    view.Sort = "Update Date ASC";
                    dt = view.ToTable();
                    if (dt.Rows.Count > 0)
                    {
                        DataColumnCollection dcCollection = dt.Columns;
                        if (dcCollection.Contains("ID") && dcCollection.Contains("CustomerID") && dcCollection.Contains("Print") && dcCollection.Contains("Pay it") && dcCollection.Contains("Ship it") && dcCollection.Contains("Add Status"))
                        {
                            dcCollection.Remove("ID");
                            dcCollection.Remove("CustomerID");
                            dcCollection.Remove("Print");
                            dcCollection.Remove("Pay it");
                            dcCollection.Remove("Ship it");
                            dcCollection.Remove("Add Status");
                        }

                        SaveFileDialog sfd = new SaveFileDialog();
                        sfd.Filter = "Excel files (*.xlsx)|*.xlsx|All files (*.*)|*.*";
                        sfd.FilterIndex = 1;
                        sfd.RestoreDirectory = true;
                        sfd.InitialDirectory = Environment.GetFolderPath(Environment.SpecialFolder.Personal);
                        if (sfd.ShowDialog() == DialogResult.OK)
                        {
                            Cursor.Current = Cursors.WaitCursor;
                            using (XLWorkbook wb = new XLWorkbook())
                            {
                                wb.Worksheets.Add(dt, "Sheet1");
                                wb.SaveAs(sfd.FileName);
                            }
                            MessageBox.Show("Export Successfully");
                        }
                        var app = new Microsoft.Office.Interop.Excel.Application();
                        app.Visible = true;
                        app.Workbooks.Open(sfd.FileName, ReadOnly: false);
                    }
                    else
                    {
                        MessageBox.Show("No Record Found");
                    }

                }
                else
                    MessageBox.Show("You can not access");
            }
            catch (Exception ex)
            {
                ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter, Function :btnInvExport_Click. Message:" + ex.Message);
                MessageBox.Show("Error:" + ex.Message);
            }
        }
        private string GetExcelCell(int nID)
        {
            string sCell = string.Empty;
            if (nID < 27)
            {
                switch (nID)
                {
                    case 0:
                        sCell = "z";
                        break;
                    case 1:
                        sCell = "A";
                        break;
                    case 2:
                        sCell = "B";
                        break;
                    case 3:
                        sCell = "C";
                        break;
                    case 4:
                        sCell = "D";
                        break;
                    case 5:
                        sCell = "E";
                        break;
                    case 6:
                        sCell = "F";
                        break;
                    case 7:
                        sCell = "G";
                        break;
                    case 8:
                        sCell = "H";
                        break;

                    case 9:
                        sCell = "I";
                        break;
                    case 10:
                        sCell = "J";
                        break;
                    case 11:
                        sCell = "K";
                        break;
                    case 12:
                        sCell = "L";
                        break;
                    case 13:
                        sCell = "M";
                        break;
                    case 14:
                        sCell = "N";
                        break;
                    case 15:
                        sCell = "O";
                        break;
                    case 16:
                        sCell = "P";
                        break;
                    case 17:
                        sCell = "Q";
                        break;
                    case 18:
                        sCell = "R";
                        break;
                    case 19:
                        sCell = "S";
                        break;
                    case 20:
                        sCell = "T";
                        break;
                    case 21:
                        sCell = "U";
                        break;
                    case 22:
                        sCell = "V";
                        break;
                    default:
                        sCell = String.Empty;
                        break;
                }
                return sCell;
            }
            else
            {
                int nDiv = nID / 26;
                int nMod = nID % 26;
                if (nMod.Equals(0))
                {
                    nDiv = nDiv - 1;
                }
                sCell = GetExcelCell(nDiv);
                sCell = sCell + GetExcelCell(nMod);
                return sCell;
            }
        }
