                            if (dtCusCreditMemo.Rows[i]["Amount"].ToString() != "")
                            {
                                dgvInvoiceList.Rows[j].Cells["Amount"].Value = Decimal.Negate(Convert.ToDecimal(dtCusCreditMemo.Rows[i]["Amount"].ToString()));
                            }
                            dgvInvoiceList.Rows[j].Cells["SalesRep"].Value = dtCusCreditMemo.Rows[i]["SalesRep"].ToString();
                            dgvInvoiceList.Rows[j].Cells["EditCount"].Value = dtCusCreditMemo.Rows[i]["InvoiceEdit"].ToString();
                            DataTable dtInvoiceNumber = new BALCreditMemo().SelectByRefNumber(new BOLCreditMemo() { RefNumber = dtCusCreditMemo.Rows[i]["Num"].ToString() });
                            if (dtInvoiceNumber.Rows.Count > 0)
                            {
                                //dgvInvoiceList.Rows[j].Cells[9].Value = dtInvoiceNumber.Rows[0]["ShipMethodID"].ToString() != "" ? (Convert.ToInt32(dtInvoiceNumber.Rows[0]["ShipMethodID"]) == 12 ? "UPS 3 Day Select" : Convert.ToInt32(dtInvoiceNumber.Rows[0]["ShipMethodID"]) == 3 ? "UPS Ground" : Convert.ToInt32(dtInvoiceNumber.Rows[0]["ShipMethodID"]) == 2 ? "UPS 2nd Day Air" : Convert.ToInt32(dtInvoiceNumber.Rows[0]["ShipMethodID"]) == 13 ? "UPS Next Day Air Saver" : Convert.ToInt32(dtInvoiceNumber.Rows[0]["ShipMethodID"]) == 1 ? "UPS Next Day Air" : "") : "";
                                dgvInvoiceList.Rows[j].Cells["VIA_Service"].Value = dtInvoiceNumber.Rows[0]["ShipmethodName"].ToString();
                            }
                            if (dtCusCreditMemo.Rows[i]["PaidInvoice"].ToString() == "0")
                            {
                                dgvInvoiceList.Rows[j].Cells["PaidStatus1"].Value = "Unpaid";
                            }

                            else if (dtCusCreditMemo.Rows[i]["PaidInvoice"].ToString() == "1")
                            {
                                dgvInvoiceList.Rows[j].Cells["PaidStatus1"].Value = "Partially Paid";
                                dgvInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#33B864");
                            }
                            else if (dtCusCreditMemo.Rows[i]["PaidInvoice"].ToString() == "2")
                            {
                                dgvInvoiceList.Rows[j].Cells["PaidStatus1"].Value = "Paid";
                                dgvInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#228B22");
                            }
                            if (dtCusCreditMemo.Rows[i]["Amount"].ToString() != "")
                            {
                                Total1 += Convert.ToDecimal(dtCusCreditMemo.Rows[i]["Amount"].ToString());
                            }
                            dgvInvoiceList.Rows[j].Cells["ShippingCost1"].Value = "";

                            //dgvInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#d60000");
                            dgvInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#F4C2C2");
                            int INVID = Convert.ToInt32(dtCusCreditMemo.Rows[i]["ID"].ToString());
                            DataTable dt = BALHistory.Select(INVID);
                            //Hiren
                            if (dtCusCreditMemo.Rows[i]["Num"].ToString().StartsWith("9000"))
                            {
                                dgvInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#FF7F7F");
                                dgvInvoiceList.Rows[j].DefaultCellStyle.ForeColor = System.Drawing.Color.Black;
                            }
                            else if (dtCusCreditMemo.Rows[i]["Num"].ToString().Contains("T") == true)
                            {
                                dgvInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#FF7F7F");
                                dgvInvoiceList.Rows[j].DefaultCellStyle.ForeColor = System.Drawing.Color.Black;
                            }
                            j++;
                        }
                        FinalTotal = Total - Total1;
                    }
                    else
                    {
                        if (dtCusInvoice.Rows.Count == 0)
                        {
                            dgvInvoiceList.Rows.Clear();
                            FinalTotal = 0;
                        }
                        else
                        {
                            FinalTotal = Total;
                        }
                    }



                    dgvInvoiceList.Sort(dgvInvoiceList.Columns[3], ListSortDirection.Ascending);
                    lblCusWiseTotal.Text = FinalTotal.ToString("N2");

                }
                //Cursor.Current = Cursors.Default;
            }
            catch (Exception ex)
            {
                ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter,Function :dtTranTo_Leave. Message:" + ex.Message);
                MessageBox.Show("Error:" + ex.Message);
            }
        }
        private void dtPenTo_Leave(object sender, EventArgs e)
        {
            try
            {
                dtCusPendingInvoice = new DataTable();
                if (ClsCommon.UserType == "Admin" || ClsCommon.UserType == "admin")
                    dtCusPendingInvoice = new BALInvoiceMaster().SelectByCustomerWisePendingInvoice(new BOLInvoiceMaster() { CustomerID = Convert.ToInt32(dgvCustomerList.CurrentRow.Cells["ID"].Value.ToString()), StartDate = dtPenFrom.Value.ToString("yyyy-MM-dd"), EndDate = dtPenTo.Value.ToString("yyyy-MM-dd"), CreatedID = 0 });
                else
                    dtCusPendingInvoice = new BALInvoiceMaster().SelectByCustomerWisePendingInvoice(new BOLInvoiceMaster() { CustomerID = Convert.ToInt32(dgvCustomerList.CurrentRow.Cells["ID"].Value.ToString()), StartDate = dtPenFrom.Value.ToString("yyyy-MM-dd"), EndDate = dtPenTo.Value.ToString("yyyy-MM-dd"), CreatedID = ClsCommon.UserID });
                if (dtCusPendingInvoice.Rows.Count > 0)
                {
                    int j = 0;
                    dgvPendingInvoice.Rows.Clear();
                    for (int i = 0; i < dtCusPendingInvoice.Rows.Count; i++)
                    {
                        dgvPendingInvoice.Rows.Add();
                        dgvPendingInvoice.Rows[j].Cells[0].Value = dtCusPendingInvoice.Rows[i]["ID"].ToString();
                        dgvPendingInvoice.Rows[j].Cells[1].Value = "Invoice";
                        dgvPendingInvoice.Rows[j].Cells[2].Value = dtCusPendingInvoice.Rows[i]["Num"].ToString();
