        public void DisplayNotes(int ID)
        {
            int cusID = 0;
            try
            {
                if (dgvCustomerList.Rows.Count > 0)
                {
                    dgInvDetail.Rows.Clear();
                    if (ID != 0)
                    {
                        cusID = Convert.ToInt32(ID);
                    }
                    else
                    {
                        cusID = Convert.ToInt32(dgvCustomerList.Rows[CustRowIndex].Cells["ID"].Value.ToString());
                    }

                    DataTable dt = ObjNoteBAL.SelectByCusID(cusID);
                    if (dt.Rows.Count > 0)
                    {

                        int iRow = 0;
                        foreach (DataRow item in dt.Rows)
                        {
                            dgInvDetail.Rows.Add();
                            dgInvDetail[0, iRow].Value = item["ID"].ToString();
                            dgInvDetail[1, iRow].Value = item["CusID"].ToString();
                            dgInvDetail[2, iRow].Value = item["Note"].ToString();
                            if (item["UseOneTime"].ToString() == "1")
                            {
                                dgInvDetail[3, iRow].Value = true;
                            }
                            if (item["UseEveryTime"].ToString() == "1")
                            {
                                dgInvDetail[4, iRow].Value = true;
                            }
                            iRow++;
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter,Function :DisplayNotes. Message:" + ex.Message);
                MessageBox.Show("Error:" + ex.Message);
            }
        }
