        private void dgvInvoiceList_CellMouseMove(object sender, DataGridViewCellMouseEventArgs e)
        {
            try
            {
                if (dgvInvoiceList.CurrentRow != null)
                {
                    dgvInvoiceList.CurrentRow.Cells["InvoiceID"].Value.ToString();
                    if (dgvInvoiceList.CurrentRow.Cells["Type"].Value != null)
                    {
                        if (dgvInvoiceList.CurrentRow.Cells["Type"].Value.ToString() == "Invoice")
                        {
                            DataTable dtInvoice = new BALInvoiceDetails().SelectByID(new BOLInvoiceDetails() { InvoiceID = Convert.ToInt32(dgvInvoiceList.CurrentRow.Cells["InvoiceID"].Value.ToString()) });
                            if (dtInvoice.Rows.Count > 0)
                            {
                                for (int i = 0; i < dtInvoice.Rows.Count; i++)
                                {
                                    if (dtInvoice.Rows[i]["ItemFullName"].ToString() == "NOTES")
                                    {
                                        //MessageBox.Show(dtInvoice.Rows[i]["Decs"].ToString());
                                        AddConnections(dgvInvoiceList.CurrentRow, dtInvoice.Rows[i]["Decs"].ToString());
                                    }
                                }
                            }
                        }
                        else
                        {
                            DataTable dtInvoice = new BALCreditMemoDetails().SelectByID(new BOLCreditMemoDetails() { InvoiceID = Convert.ToInt32(dgvInvoiceList.CurrentRow.Cells["InvoiceID"].Value.ToString()) });
                            if (dtInvoice.Rows.Count > 0)
                            {
                                for (int i = 0; i < dtInvoice.Rows.Count; i++)
                                {
                                    if (dtInvoice.Rows[i]["ItemFullName"].ToString() == "NOTES")
                                    {
                                        //MessageBox.Show(dtInvoice.Rows[i]["Decs"].ToString());
                                        AddConnections(dgvInvoiceList.CurrentRow, dtInvoice.Rows[i]["Decs"].ToString());
                                    }
                                }
                            }
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                MessageBox.Show(ex.Message);
                ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter,Function :dgvInvoiceList_CellMouseMove. Message:" + ex.Message);
            }
        }
        private void dgvAllInvoiceList_FilterStringChanged(object sender, EventArgs e)
        {
            DataTable dtAll = new DataTable();
            try
            {
                if (this.dgvAllInvoiceList.FilterString == "")
                    dtAll = dtFilter;
                else
                    dtAll = dtFilter.Select(this.dgvAllInvoiceList.FilterString).CopyToDataTable();

                this.dgvAllInvoiceList.AutoGenerateColumns = false;
                //this.dgvAllInvoiceList.DataSource = dtAll; // datatable
                int j = 0; decimal AmountTotal = 0; decimal OpenTotal = 0; decimal TotalProfit = 0;
                dgvAllInvoiceList.Rows.Clear();
                for (int i = 0; i < dtAll.Rows.Count; i++)
                {
                    try
                    {
                        dgvAllInvoiceList.Rows.Add();
                        DataTable dtcustomer = new DataTable();
                        if (InvoiceType == "Invoice&CreditMemo")
                        {
                            dgvAllInvoiceList.Rows[j].Cells["TYPE1"].Value = dtAll.Rows[i]["Type"].ToString();
                        }
                        else
                        {
                            dgvAllInvoiceList.Rows[j].Cells["TYPE1"].Value = "";
                        }
                        if (IsCreditMemo == false && (dtAll.Rows[i]["Type"].ToString() == "Invoice" || dtAll.Rows[i]["Type"].ToString() == ""))
                        {
                            if (dtAll.Rows[i]["NUM"].ToString() != "")
                            {
                                dtshipping = BALFedEx.SelectByRefNo(dtAll.Rows[i]["Num"].ToString());
                                if (dtshipping.Rows.Count > 0)
                                {
                                    int LastRow = dtshipping.Rows.Count - 1;
                                    if (dtshipping.Rows[LastRow]["TotalCost"].ToString() != "")
                                    {
                                        dgvAllInvoiceList.Rows[j].Cells["ShipCharges"].Value = "Shipped " + dtshipping.Rows[LastRow]["TotalCost"].ToString();
                                    }
                                    else
                                    {
                                        dgvAllInvoiceList.Rows[j].Cells["ShipCharges"].Value = "Shipped";
                                    }
                                    //dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = Color.Brown;
                                    dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#b7a591");
                                    dgvAllInvoiceList.Rows[j].Cells["ShipStatus"].Value = "SHIPPED";
                                }
                                else
                                {
                                    if (dtAll.Rows[i]["ShipStatus"].ToString() != "")
                                    {
                                        dgvAllInvoiceList.Rows[j].Cells["ShipStatus"].Value = dtAll.Rows[i]["ShipStatus"].ToString();
                                    }
                                }
                            }
                            DataTable dtInvoice = new BALInvoiceDetails().SelectByID(new BOLInvoiceDetails() { InvoiceID = Convert.ToInt32(dtAll.Rows[i]["ID"].ToString()) });
                            if (dtInvoice.Rows.Count > 0)
                            {
                                DataRow[] drShipping = dtInvoice.Select("[ItemFullName]='shipping'");
                                {
                                    if (IsCreditMemo == false && (dtAll.Rows[i]["Type"].ToString() == "Invoice" || dtAll.Rows[i]["Type"].ToString() == ""))
                                    {
                                        if (drShipping.Length > 0)
                                        {
                                            DataTable dtShipping = drShipping.CopyToDataTable();
                                            dgvAllInvoiceList.Rows[j].Cells["ShippingCost"].Value = "$" + dtShipping.Rows[0]["Rate"].ToString();
                                        }
                                        else
                                        {
                                            dgvAllInvoiceList.Rows[j].Cells["ShippingCost"].Value = "$0.00";
                                        }
                                    }
                                    else
                                    {
                                        dgvAllInvoiceList.Rows[j].Cells["ShippingCost"].Value = "";
                                    }
                                }
                                DataRow[] drNote = dtInvoice.Select("[ItemFullName]='NOTES'");
                                {
                                    if (drNote.Length > 0)
                                    {
                                        dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = Color.SkyBlue;
                                    }
                                }
                            }
                            decimal TotalDetails = 0;
                            DataTable newDetails = new BALInvoiceDetails().SelectByInvID(new BOLInvoiceDetails() { InvoiceID = Convert.ToInt32(dtAll.Rows[i]["ID"].ToString()) });
                            if (newDetails.Rows.Count > 0)
                            {

                                foreach (DataRow dr in newDetails.Rows)
                                {
                                    if (dr["Cost"].ToString() == "")
                                    {
                                        dr["Cost"] = 0.00;
                                    }
                                    if (dr["Cost"].ToString() != "0.00")
                                    {
                                        TotalDetails += Convert.ToDecimal(dr["Quantity"].ToString()) * (Convert.ToDecimal(dr["Rate"].ToString()) - Convert.ToDecimal(dr["Cost"].ToString()));
                                    }
                                }
                            }
                            dgvAllInvoiceList.Rows[j].Cells["Profit"].Value = string.Concat(decimal.Round(TotalDetails, 2));
                            if (dtAll.Rows[i]["Amount"].ToString() != "0.00" && dtAll.Rows[i]["Amount"].ToString() != "")
                            {
                                dgvAllInvoiceList.Rows[j].Cells["ProfitPercentage"].Value = string.Concat(decimal.Round((Convert.ToDecimal(TotalDetails) / Convert.ToDecimal(dtAll.Rows[i]["Amount"].ToString())) * 100, 2), '%');
                            }
                            else
                            {
                                dgvAllInvoiceList.Rows[j].Cells["ProfitPercentage"].Value = "0%";
                            }
                            dtcustomer = new BALInvoiceMaster().SelectByCusID(new BOLInvoiceMaster() { CustomerID = Convert.ToInt32(dtAll.Rows[i]["CustomerID"].ToString()) });
                            if (dtAll.Rows[i]["OPEN BALANCE"].ToString() != "")
                            {
                                dgvAllInvoiceList.Rows[j].Cells["OpenBalance"].Value = Convert.ToDecimal(dtAll.Rows[i]["OPEN BALANCE"].ToString());
                            }
                            DataTable dtInvoiceNumber = new BALInvoiceMaster().SelectByRefNumber(new BOLInvoiceMaster() { RefNumber = dtAll.Rows[i]["NUM"].ToString() });
                            if (dtInvoiceNumber.Rows.Count > 0)
                            {
                                dgvAllInvoiceList.Rows[j].Cells["VIA_Services"].Value = dtInvoiceNumber.Rows[0]["ShipmethodName"].ToString();
                            }
                            if (dtAll.Rows[i]["PendingInvoice"].ToString() == "Panding")
                            {
                                dgvAllInvoiceList.Rows[j].Cells["PendingInvoice"].Value = "Panding";
                            }
                            if (dtAll.Rows[i]["AMOUNT"].ToString() != "")
                            {
                                dgvAllInvoiceList.Rows[j].Cells["InvoiceAmount"].Value = Convert.ToDecimal(dtAll.Rows[i]["AMOUNT"].ToString());
                            }
                            if (dtAll.Rows[i]["PaidStatus"].ToString() == "Unpaid")
                            {
                                dgvAllInvoiceList.Rows[j].Cells["PaidStatus"].Value = "Unpaid";
                            }
                            else if (dtAll.Rows[i]["PaidStatus"].ToString() == "Partially Paid")
                            {
                                dgvAllInvoiceList.Rows[j].Cells["PaidStatus"].Value = "Partially Paid";
                                dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#90EE90");
                            }
                            else if (dtAll.Rows[i]["PaidStatus"].ToString() == "Paid")
                            {
                                dgvAllInvoiceList.Rows[j].Cells["PaidStatus"].Value = "Paid";
                                dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#228B22");
                            }
                            if (dtAll.Rows[i]["AMOUNT"].ToString() != "")
                            {
                                AmountTotal += Convert.ToDecimal(dtAll.Rows[i]["AMOUNT"].ToString());
                            }
                            if (dtAll.Rows[i]["OPEN BALANCE"].ToString() != "")
                            {
                                OpenTotal += Convert.ToDecimal(dtAll.Rows[i]["OPEN BALANCE"].ToString());
                            }
                            if (TotalDetails != 0)
                            {
                                TotalProfit += decimal.Round(TotalDetails, 2);
                            }
                        }
                        else
                        {
                            DataTable dtInvoice = new BALCreditMemoDetails().SelectByID(new BOLCreditMemoDetails() { InvoiceID = Convert.ToInt32(dtAll.Rows[i]["ID"].ToString()) });
                            if (dtInvoice.Rows.Count > 0)
                            {
                                DataRow[] drNote = dtInvoice.Select("[ItemFullName]='NOTES'");
                                {
                                    if (drNote.Length > 0)
                                    {
                                        dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = Color.SkyBlue;
                                    }
                                }
                            }
                            if (dtAll.Rows[i]["ShipStatus"].ToString() != "")
                            {
                                dgvAllInvoiceList.Rows[j].Cells["ShipStatus"].Value = dtAll.Rows[i]["ShipStatus"].ToString();
                            }
                            dgvAllInvoiceList.Rows[j].Cells["Profit"].Value = "";
                            dgvAllInvoiceList.Rows[j].Cells["ProfitPercentage"].Value = "";
                            dtcustomer = new BALCreditMemo().SelectByCusID(Convert.ToInt32(dtAll.Rows[i]["CustomerID"].ToString()));
                            if (dtAll.Rows[i]["OPEN BALANCE"].ToString() != "")
                            {
                                dgvAllInvoiceList.Rows[j].Cells["OpenBalance"].Value = Decimal.Negate(Convert.ToDecimal(dtAll.Rows[i]["OPEN BALANCE"].ToString()));
                            }
                            DataTable dtInvoiceNumber = new BALCreditMemo().SelectByRefNumber(new BOLCreditMemo() { RefNumber = dtAll.Rows[i]["NUM"].ToString() });
                            if (dtInvoiceNumber.Rows.Count > 0)
                            {
                                dgvAllInvoiceList.Rows[j].Cells["VIA_Services"].Value = dtInvoiceNumber.Rows[0]["ShipmethodName"].ToString();
                            }
                            dgvAllInvoiceList.Rows[j].Cells["PendingInvoice"].Value = "";
                            if (dtAll.Rows[i]["AMOUNT"].ToString() != "")
                            {
                                dgvAllInvoiceList.Rows[j].Cells["InvoiceAmount"].Value = Decimal.Negate(Convert.ToDecimal(dtAll.Rows[i]["AMOUNT"].ToString()));
                            }
                            if (dtAll.Rows[i]["PaidStatus"].ToString() == "Unpaid")
                            {
                                dgvAllInvoiceList.Rows[j].Cells["PaidStatus"].Value = "Unpaid";
                            }
                            else if (dtAll.Rows[i]["PaidStatus"].ToString() == "Partially Paid")
                            {
                                dgvAllInvoiceList.Rows[j].Cells["PaidStatus"].Value = "Partially Paid";
                                dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#90EE90");
                            }
                            else if (dtAll.Rows[i]["PaidStatus"].ToString() == "Paid")
                            {
                                dgvAllInvoiceList.Rows[j].Cells["PaidStatus"].Value = "Paid";
                                dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#228B22");
                            }
                            if (dtAll.Rows[i]["AMOUNT"].ToString() != "")
                            {
                                AmountTotal += Decimal.Negate(Convert.ToDecimal(dtAll.Rows[i]["AMOUNT"].ToString()));
                            }
                            if (dtAll.Rows[i]["OPEN BALANCE"].ToString() != "")
                            {
                                OpenTotal += Decimal.Negate(Convert.ToDecimal(dtAll.Rows[i]["OPEN BALANCE"].ToString()));
                            }
                            //dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#d60000");
                            dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#F4C2C2");
                        }
                        dgvAllInvoiceList.Rows[j].Cells["InvID"].Value = dtAll.Rows[i]["ID"].ToString();
                        dgvAllInvoiceList.Rows[j].Cells["CustomerID"].Value = dtAll.Rows[i]["CustomerID"].ToString();
                        int Count = 0;
                        Count = dtcustomer.Rows.Count;
                        if (Count == 1)
                        {
                            dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#EF6262");
                        }

                        dgvAllInvoiceList.Rows[j].Cells["NoOfInvoice"].Value = Count;
                        dgvAllInvoiceList.Rows[j].Cells["CustomerNm"].Value = dtAll.Rows[i]["CUSTOMER"].ToString();
                        if (dtAll.Rows[i]["NUM"].ToString() != "")
                        {
                            //dgvAllInvoiceList.Rows[j].Cells[4].Value = Convert.ToInt32(dtAllInvoice.Rows[i]["Num"].ToString());
                            dgvAllInvoiceList.Rows[j].Cells["InvoiceNum"].Value = dtAll.Rows[i]["NUM"].ToString();
                        }
                        if (dtAll.Rows[i]["Update Date"].ToString() != "")
                        {
                            DateTime date = Convert.ToDateTime(dtAll.Rows[i]["Update Date"].ToString());
                            dgvAllInvoiceList.Rows[j].Cells["InvoiceDate"].Value = date;
                        }
                        if (dtAll.Rows[i]["Update Time"].ToString() != "")
                        {
                            dgvAllInvoiceList.Rows[j].Cells["TIME"].Value = dtAll.Rows[i]["Update Time"].ToString();
                        }
                        if (dtAll.Rows[i]["Create Date"].ToString() != "")
                        {
                            DateTime date = Convert.ToDateTime(dtAll.Rows[i]["Create Date"].ToString());
                            dgvAllInvoiceList.Rows[j].Cells["CREATEDATE"].Value = date;
                        }
                        if (dtAll.Rows[i]["Create Time"].ToString() != "")
                        {
                            dgvAllInvoiceList.Rows[j].Cells["CREATETIME"].Value = dtAll.Rows[i]["Create Time"].ToString();
                        }
                        if (dtAll.Rows[i]["DUE DATE"].ToString() != "")
                        {
                            DateTime date = Convert.ToDateTime(dtAll.Rows[i]["DUE DATE"].ToString());
                            dgvAllInvoiceList.Rows[j].Cells["DueDate"].Value = date;
                        }
                        dgvAllInvoiceList.Rows[j].Cells["Term"].Value = dtAll.Rows[i]["TERMS"].ToString();

                        dgvAllInvoiceList.Rows[j].Cells["Rep"].Value = dtAll.Rows[i]["SalesRep"].ToString();
                        dgvAllInvoiceList.Rows[j].Cells["CountEdit"].Value = dtAll.Rows[i]["No Of Times Edit"].ToString();

                        if (dtAll.Rows[i]["ErrorLog"].ToString() != "")
                        {
                            dgvAllInvoiceList.Rows[j].Cells["Error"].Value = "ViewError";
                        }
                        j++;
                    }
                    catch (Exception ex)
                    {
                        ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter, Function :LoadAllInvoices. Message:" + ex.Message);
                        MessageBox.Show("Error:" + ex.Message);
                    }
                }
                dgvAllInvoiceList.Sort(dgvAllInvoiceList.Columns["NoOfInvoice"], ListSortDirection.Ascending);
                lblAmountTotal.Text = AmountTotal.ToString("N2");
                lblOpenTotal.Text = OpenTotal.ToString("N2");
                lblTotalProfitBalance.Text = TotalProfit.ToString("N2");
                dgvAllInvoiceList.Enabled = true;
                dgvAllInvoiceList.Refresh();
            }
            catch (Exception ex)
            {
                MessageBox.Show(ex.Message);
                ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter,Function :dgvAllInvoiceList_FilterStringChanged. Message:" + ex.Message);
            }
        }
        private void dgvAllInvoiceList_CellDoubleClick_1(object sender, DataGridViewCellEventArgs e)
        {
            try
            {
                if (IsCreditMemo == true || (dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value.ToString() == "Credit Memo"))
                {
                    if (ClsCommon.FunctionVisibility("CreditMemoUpdate", "CustomerCenter"))
                    {
                        ClsCommon.ObjCreditMemo.LoadTable();
                        ClsCommon.ObjCreditMemo.EditableField();
                        ClsCommon.TaxWithoutTax = "";
                        ClsCommon.ObjCreditMemo.Show();
                        ClsCommon.ObjCreditMemo.LoadData(dgvAllInvoiceList.CurrentRow.Cells["InvID"].Value.ToString());
                        ClsCommon.ObjCreditMemo.AllowLowestPrice();
                        ClsCommon.ObjCreditMemo.CheckDate();
                    }
                }
                else if (IsReceivePayment == true || (dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value.ToString() == "ReceivePayment"))
                {
                    FrmPaymentDetail frm = new FrmPaymentDetail();
                    frm.Show();
                    frm.PayID = Convert.ToInt32(dgvAllInvoiceList.CurrentRow.Cells["PayID1"].Value.ToString());
                    frm.loadData(Convert.ToInt32(dgvAllInvoiceList.CurrentRow.Cells["InvID"].Value.ToString()));
                    frm.CheckEnable();
                    frm.BringToFront();
                    //FrmPaymentDetail frm = new FrmPaymentDetail();
                    //frm.Show();
                    //frm.CustomerLoad(Convert.ToInt32(dgvCustomerList.Rows[CustRowIndex].Cells["ID"].Value.ToString()));
                    //frm.CheckEnable();
                    //frm.BringToFront();
                }
                else
                {
                    if (ClsCommon.FunctionVisibility("InvUpdate", "CustomerCenter"))
                    {
                        ClsCommon.ObjInvoiceMaster.LoadTable();
                        ClsCommon.ObjInvoiceMaster.EditableField();
                        ClsCommon.TaxWithoutTax = "";
                        ClsCommon.ObjInvoiceMaster.Show();
                        ClsCommon.ObjInvoiceMaster.LoadData(dgvAllInvoiceList.CurrentRow.Cells["InvID"].Value.ToString());
                        ClsCommon.ObjInvoiceMaster.AllowLowestPrice();
                        ClsCommon.ObjInvoiceMaster.CheckDate();
                        //ClsCommon.ObjInvoiceMaster.DisplayNotes();
                        //}
                    }
                    else
                        MessageBox.Show("You can not access");
                }
            }
            catch (Exception ex)
            {
                ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter,Function :dgvAllInvoiceList_CellContentDoubleClick. Message:" + ex.Message);
                MessageBox.Show("Error:" + ex.Message);
            }

        }
        private void dgvAllInvoiceList_CellContentClick_1(object sender, DataGridViewCellEventArgs e)
        {
            ShipAddress = "";
            try
            {
                //Nidhi Change Index
                if (e.RowIndex == -1)
                {
                    if (dgvAllInvoiceList.SortString == "")
                    {
                        dgvAllInvoiceList.Sort(dgvAllInvoiceList.Columns[e.ColumnIndex], ListSortDirection.Ascending);
                    }
                    else
                    {
                        dgvAllInvoiceList.Sort(dgvAllInvoiceList.Columns[e.ColumnIndex], ListSortDirection.Descending);

                    }
                }
                else if (e.RowIndex > -1)
                {
                    if (e.ColumnIndex == 18)
                    {
                        //if (dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value == null)
                        //{
                        //    dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value = "";
                        //}
                        if (IsCreditMemo == true || dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value.ToString() == "Credit Memo")
                        {
                            Int32 ID = Convert.ToInt32(dgvAllInvoiceList.Rows[e.RowIndex].Cells["InvID"].Value);
                            objBOLCreditMemo.ID = Convert.ToInt32(ID);
                            DataTable dtInv = new BALCreditMemo().SelectByID(objBOLCreditMemo);
                            if (dtInv.Rows.Count > 0)
                            {
                                string Error = dtInv.Rows[0]["ErrorLog"].ToString();
                                MessageBox.Show(Error);
                            }
                        }
                        else
                        {
                            Int32 ID = Convert.ToInt32(dgvAllInvoiceList.Rows[e.RowIndex].Cells["InvID"].Value);
                            objBOLInvoice.ID = Convert.ToInt32(ID);
                            DataTable dtInv = new BALInvoiceMaster().SelectByID(objBOLInvoice);
                            if (dtInv.Rows.Count > 0)
                            {
                                string Error = dtInv.Rows[0]["ErrorLog"].ToString();
                                MessageBox.Show(Error);
                            }
                        }
                    }
                    if (e.ColumnIndex == 21)
                    {
                        //if(dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value==null)
                        //{
                        //    dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value = "";
                        //}
                        //if (IsCreditMemo == true && (dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value.ToString() == "Credit Memo"|| dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value.ToString() == ""))
                        if (IsCreditMemo == true || dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value.ToString() == "Credit Memo")
                        {
                            int ID1 = Convert.ToInt32(dgvAllInvoiceList.CurrentRow.Cells["InvID"].Value);
                            PrintCreditMemo(ref ID1);
                            ClsCommon.INVID = ID1;
                            ClsCommon.ObjInvoiceMaster.InvoicePrintHistory(ClsCommon.INVID);
                            ClsCommon.ObjInvoiceMaster.PrintSave(ClsCommon.INVID);
                        }
                        else
                        {
                            int ID1 = Convert.ToInt32(dgvAllInvoiceList.CurrentRow.Cells["InvID"].Value);
                            PrintINV(ref ID1);
                            ClsCommon.INVID = ID1;
                            ClsCommon.ObjInvoiceMaster.InvoicePrintHistory(ClsCommon.INVID);
                            ClsCommon.ObjInvoiceMaster.PrintSave(ClsCommon.INVID);
                        }

                    }
                    else if (e.ColumnIndex == 22)
                    {
                        //if (dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value == null)
                        //{
                        //    dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value = "";
                        //}
                        if (IsCreditMemo == false && (dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value.ToString() == "Invoice" || dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value.ToString() == ""))
                        {


                            FrmPaymentDetail frm = new FrmPaymentDetail();
                            frm.Show();
                            frm.loadData(Convert.ToInt32(dgvAllInvoiceList.CurrentRow.Cells["InvID"].Value.ToString()));
                            frm.CheckEnable();
                            frm.BringToFront();
                        }
                        else
                        {
                            MessageBox.Show("Credit Memo Not Allow Payment");
                        }
                    }
                    else if (e.ColumnIndex == 26)
                    {

                        if (IsCreditMemo == false && (dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value.ToString() == "Invoice" || dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value.ToString() == ""))
                        {
                            dtshipping = BALFedEx.SelectByRefNo(dgvAllInvoiceList.CurrentRow.Cells["InvoiceNum"].Value.ToString());
                            if (dtshipping.Rows.Count > 0)
                            {
                                int LastRow = dtshipping.Rows.Count - 1;
                                if (dtshipping.Rows[LastRow]["TotalCost"].ToString() != "")
                                {
                                    dgvAllInvoiceList.CurrentRow.Cells["ShipCharges"].Value = "Shipped " + dtshipping.Rows[LastRow]["TotalCost"].ToString();
                                }
                                else
                                {
                                    dgvAllInvoiceList.CurrentRow.Cells["ShipCharges"].Value = "Shipped";
                                }
                                //dgvAllInvoiceList.CurrentRow.DefaultCellStyle.BackColor = Color.Brown;
                                dgvAllInvoiceList.CurrentRow.DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#b7a591");
                                dgvAllInvoiceList.CurrentRow.Cells["ShipStatus"].Value = "SHIPPED";
                            }

                            ClsCommon.objUPS.BringToFront();
                            ClsCommon.objUPS.StartPosition = FormStartPosition.Manual;
                            DataTable DT = new DataTable();
                            DT = new BALInvoiceMaster().SelectByID(new BOLInvoiceMaster() { ID = Convert.ToInt32(dgvAllInvoiceList.CurrentRow.Cells["InvID"].Value.ToString()) });
                            if (DT.Rows.Count > 0)
                            {

                                if (DT.Rows[0]["TermName"].ToString() == "COD")
                                {
                                    ClsCommon.COD = true;
                                    ClsCommon.CODAmount = DT.Rows[0]["Total"].ToString();
                                }
                                else
                                {
                                    ClsCommon.COD = false;
                                }
                                ClsCommon.Weight = 0;
                                DataTable dt2 = new BALItemMaster().GetWeight();
                                DataView dv = null;
                                dv = dt2.DefaultView;
                                DataTable dt1 = new BALInvoiceDetails().SelectByID(new BOLInvoiceDetails() { InvoiceID = Convert.ToInt32(dgvAllInvoiceList.CurrentRow.Cells["InvID"].Value.ToString()) });
                                for (int n = 0; n < dt1.Rows.Count; n++)
                                {
                                    dv.RowFilter = "ItemName='" + dt1.Rows[n]["ItemFullName"].ToString() + "'";
                                    if (dv.Count > 0)
                                    {
                                        if (dv.ToTable().Rows[0]["Weight"].ToString() != "")
                                        {
                                            decimal TotalWeight = 0;
                                            if (dv.ToTable().Rows[0]["Weight"].ToString() != "" && dt1.Rows[n]["Quantity"].ToString() != "")
                                            {
                                                TotalWeight = Math.Round(Convert.ToDecimal(dv.ToTable().Rows[0]["Weight"].ToString()) * Convert.ToDecimal(dt1.Rows[n]["Quantity"].ToString()), 2);
                                            }
                                            if (TotalWeight != 0)
                                            {
                                                ClsCommon.Weight += TotalWeight;
                                            }
                                            else
                                            {
                                                ClsCommon.Weight += Convert.ToDecimal(dv.ToTable().Rows[0]["Weight"].ToString());
                                            }
                                        }
                                    }

                                }

                                ClsCommon.RefNumber = DT.Rows[0]["RefNumber"].ToString();
                                //ClsCommon.ShipMethod = DT.Rows[0]["ShipMethodID"].ToString() != "" ? (Convert.ToInt32(DT.Rows[0]["ShipMethodID"]) == 12 ? "UPS 3 Day Select" : Convert.ToInt32(DT.Rows[0]["ShipMethodID"]) == 03 ? "UPS Ground" : Convert.ToInt32(DT.Rows[0]["ShipMethodID"]) == 02 ? "UPS 2nd Day Air" : Convert.ToInt32(DT.Rows[0]["ShipMethodID"]) == 13 ? "UPS Next Day Air Saver" : Convert.ToInt32(DT.Rows[0]["ShipMethodID"]) == 01 ? "UPS Next Day Air" : Convert.ToInt32(DT.Rows[0]["ShipMethodID"]) == 0 ? "Select Service" : "") : "";
                                ClsCommon.ShipMethod = DT.Rows[0]["ShipMethod"].ToString();
                                ClsCommon.objUPS.Total = dgvAllInvoiceList.CurrentRow.Cells["InvoiceAmount"].Value.ToString();
                                ClsCommon.objUPS.Location = new Point(230, 80);
                                ClsCommon.objUPS.Clear1();
                                ClsCommon.objUPS.ShowDialog();
                                dtshipping = BALFedEx.SelectByRefNo(dgvAllInvoiceList.CurrentRow.Cells["InvoiceNum"].Value.ToString());
                                if (dtshipping.Rows.Count > 0)
                                {
                                    int LastRow = dtshipping.Rows.Count - 1;
                                    if (dtshipping.Rows[LastRow]["TotalCost"].ToString() != "")
                                    {
                                        dgvAllInvoiceList.CurrentRow.Cells["ShipCharges"].Value = "Shipped " + dtshipping.Rows[LastRow]["TotalCost"].ToString();
                                    }
                                    else
                                    {
                                        dgvAllInvoiceList.CurrentRow.Cells["ShipCharges"].Value = "Shipped";
                                    }
                                    //dgvAllInvoiceList.CurrentRow.DefaultCellStyle.BackColor = Color.Brown;
                                    dgvAllInvoiceList.CurrentRow.DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#b7a591");
                                    dgvAllInvoiceList.CurrentRow.Cells["ShipStatus"].Value = "SHIPPED";

                                }

                            }
                        }
                        else
                        {
                            MessageBox.Show("Credit Memo Not Allow Ship it");
                        }
                    }
                    else if (e.ColumnIndex == 29)
                    {
                        //if (dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value == null)
                        //{
                        //    dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value = "";
                        //}
                        if (IsCreditMemo == false && (dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value.ToString() == "Invoice" || dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value.ToString() == ""))
