        private void dgvAllInvoiceList_CellMouseMove_1(object sender, DataGridViewCellMouseEventArgs e)
        {
            if (dgvAllInvoiceList.CurrentRow != null)
            {
                dgvAllInvoiceList.CurrentRow.Cells["InvID"].Value.ToString();
                if (dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value == null)
                {
                    dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value = "";
                }
                if (IsCreditMemo == false && (dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value.ToString() == "Invoice" || dgvAllInvoiceList.CurrentRow.Cells["TYPE1"].Value.ToString() == ""))
                {
                    DataTable dtInvoice = new BALInvoiceDetails().SelectByID(new BOLInvoiceDetails() { InvoiceID = Convert.ToInt32(dgvAllInvoiceList.CurrentRow.Cells["InvID"].Value.ToString()) });
                    if (dtInvoice.Rows.Count > 0)
                    {
                        for (int i = 0; i < dtInvoice.Rows.Count; i++)
                        {
                            if (dtInvoice.Rows[i]["ItemFullName"].ToString() == "NOTES")
                            {

                                //MessageBox.Show(dtInvoice.Rows[i]["Decs"].ToString());
                                AddConnections(dgvAllInvoiceList.CurrentRow, dtInvoice.Rows[i]["Decs"].ToString());

                            }
                        }
                    }
                }
                else
                {
                    DataTable dtInvoice = new BALCreditMemoDetails().SelectByID(new BOLCreditMemoDetails() { InvoiceID = Convert.ToInt32(dgvAllInvoiceList.CurrentRow.Cells["InvID"].Value.ToString()) });
                    if (dtInvoice.Rows.Count > 0)
                    {
                        for (int i = 0; i < dtInvoice.Rows.Count; i++)
                        {
                            if (dtInvoice.Rows[i]["ItemFullName"].ToString() == "NOTES")
                            {

                                //MessageBox.Show(dtInvoice.Rows[i]["Decs"].ToString());
                                AddConnections(dgvAllInvoiceList.CurrentRow, dtInvoice.Rows[i]["Decs"].ToString());

                            }
                        }
                    }
                }
            }
        }
