        public void ColourViseInvoiceLoad()
        {
            if (IsReceivePayment == true)
            {
                if (cmbColour.SelectedIndex == 0)
                {
                    try
                    {
                        LoadAllInvoices();
                    }
                    catch (Exception ex)
                    {
                        MessageBox.Show(ex.Message);
                    }
                }
                else if (cmbColour.SelectedIndex == 1)
                {
                    DataTable dtAll = new DataTable();
                    if (dtFilter.Rows.Count > 0)
                    {
                        try
                        {
                            //string Filter = "(Convert([NoOfInvoice],System.String) IN ('', '1'))";
                            string Filter = "([Num] LIKE '9000%' OR [Num] LIKE '%T%')";

                            dtAll = dtFilter.Select(Filter).CopyToDataTable();

                            if (dtAll.Rows.Count > 0)
                            {
                                this.dgvAllInvoiceList.AutoGenerateColumns = false;
                                //this.dgvAllInvoiceList.DataSource = dtAll; // datatable
                                int j = 0; decimal Total = 0; decimal OpenTotal = 0; decimal TotalProfit = 0;
                                dgvAllInvoiceList.Rows.Clear();
                                for (int i = 0; i < dtAll.Rows.Count; i++)
                                {
                                    try
                                    {
                                        dgvAllInvoiceList.Rows.Add();
                                        dgvAllInvoiceList.Rows[j].Cells["InvID"].Value = dtAll.Rows[i]["ID"].ToString();
                                        dgvAllInvoiceList.Rows[j].Cells["PayID1"].Value = dtAll.Rows[i]["PayID1"].ToString();

                                        dgvAllInvoiceList.Rows[j].Cells["InvoiceNum"].Value = dtAll.Rows[i]["NUM"].ToString();

                                        if (dtAll.Rows[i]["Create Date"].ToString() != "")
                                        {
                                            DateTime Date = Convert.ToDateTime(dtAll.Rows[i]["Create Date"].ToString());
                                            dgvAllInvoiceList.Rows[j].Cells["CREATEDATE"].Value = Date;
                                            dgvAllInvoiceList.Rows[j].Cells["CREATETIME"].Value = Date.ToString("HH:mm:ss");
                                        }

                                        dgvAllInvoiceList.Rows[j].Cells["Term"].Value = dtAll.Rows[i]["TERMS"].ToString();
                                        if (dtAll.Rows[i]["Amount"].ToString() != "")
                                        {
                                            dgvAllInvoiceList.Rows[j].Cells["InvoiceAmount"].Value = Convert.ToDecimal(dtAll.Rows[i]["Amount"].ToString());
                                        }
                                        if (dtAll.Rows[i]["PaidStatus"].ToString() == "Partially Paid")
                                        {
                                            dgvAllInvoiceList.Rows[j].Cells["PaidStatus"].Value = "Partially Paid";
                                            dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#33B864");
                                            //Hiren
                                            //dgvInvoiceList.Rows[j].DefaultCellStyle.ForeColor = System.Drawing.Color.White;
                                        }
                                        else if (dtAll.Rows[i]["PaidStatus"].ToString() == "Paid")
                                        {
                                            dgvAllInvoiceList.Rows[j].Cells["PaidStatus"].Value = "Paid";
                                            dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#228B22");
                                            //Hiren
                                            dgvAllInvoiceList.Rows[j].DefaultCellStyle.ForeColor = System.Drawing.Color.White;
                                        }
                                        if (dtAll.Rows[i]["Amount"].ToString() != "")
                                        {
                                            Total += Convert.ToDecimal(dtAll.Rows[i]["Amount"].ToString());
                                        }
                                        if (dtAll.Rows[i]["OPEN BALANCE"].ToString() != "")
                                        {
                                            dgvAllInvoiceList.Rows[j].Cells["OpenBalance"].Value = Convert.ToDecimal(dtAll.Rows[i]["OPEN BALANCE"].ToString());
                                        }
                                        if (dtAll.Rows[i]["CUSTOMER"].ToString() != "")
                                        {
                                            dgvAllInvoiceList.Rows[j].Cells["CustomerNm"].Value = dtAll.Rows[i]["CUSTOMER"].ToString();
                                        }
                                        if (dtAll.Rows[i]["NUM"].ToString().StartsWith("9000"))
                                        {
                                            dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#FF7F7F");
                                            dgvAllInvoiceList.Rows[j].DefaultCellStyle.ForeColor = System.Drawing.Color.Black;
                                        }
                                        else if (dtAll.Rows[i]["NUM"].ToString().Contains("T") == true)
                                        {
                                            dgvAllInvoiceList.Rows[j].DefaultCellStyle.BackColor = System.Drawing.ColorTranslator.FromHtml("#FF7F7F");
                                            dgvAllInvoiceList.Rows[j].DefaultCellStyle.ForeColor = System.Drawing.Color.Black;
                                        }
                                        j++;
                                    }
                                    catch (Exception ex)
                                    {
                                        ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter, Function :LoadAllInvoices. Message:" + ex.Message);
                                        MessageBox.Show("Error:" + ex.Message);
                                    }
                                }
                                dgvAllInvoiceList.Sort(dgvAllInvoiceList.Columns["NoOfInvoice"], ListSortDirection.Ascending);
                                lblAmountTotal.Text = Total.ToString("N2");
                                lblOpenTotal.Text = OpenTotal.ToString("N2");
                                lblTotalProfitBalance.Text = TotalProfit.ToString("N2");
                            }
                            else
                            {
                                dgvAllInvoiceList.Rows.Clear();
                                lblAmountTotal.Text = "0.00";
                                lblOpenTotal.Text = "0.00";
                                lblTotalProfitBalance.Text = "0.00";
