        private void dgvAllInvoiceList_SortCompare(object sender, DataGridViewSortCompareEventArgs e)
        {
            try
            {
                if (e.CellValue1 != null && e.CellValue2 != null)
                {
                    if (e.Column.Index == 4 || e.Column.Index == 5 || e.Column.Index == 6 || e.Column.Index == 7 || e.Column.Index == 13 || e.Column.Index == 23 || e.Column.Index == 24 || e.Column.Index == 25 || e.Column.Index == 27)
                    {
                        e.SortResult = decimal.Parse(e.CellValue1.ToString().Replace("%", "").Replace("CM", "").Replace("$", "")).CompareTo(decimal.Parse(e.CellValue2.ToString().Replace("CM", "").Replace("$", "").Replace("%", "")));
                        e.Handled = true;
                    }
                }

            }
            catch (Exception ex)
            {
                ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter,Function :dgvAllInvoiceList_SortCompare. Message:" + ex.Message);
            }
        }
