        private void btnexport_Click(object sender, EventArgs e)
        {
            try
            {
                if (ClsCommon.FunctionVisibility("InvExport", "CustomerCenter"))
                {
                    DataTable dt = new DataTable();

                    // Create DataTable columns based on DataGridView columns
                    foreach (DataGridViewColumn column in dgvInvoiceList.Columns)
                    {
                        dt.Columns.Add(column.HeaderText);
                    }
                    // Add rows from DataGridView to DataTable
                    foreach (DataGridViewRow row in dgvInvoiceList.Rows)
                    {
                        dt.Rows.Add();
                        foreach (DataGridViewCell cell in row.Cells)
                        {
                            if (cell.FormattedValue != null)
                            {
                                dt.Rows[dt.Rows.Count - 1][cell.ColumnIndex] = cell.FormattedValue.ToString();
                            }
                        }
                    }
                    // Sort the DataTable by "Update Date"
                    DataView view = dt.DefaultView;
                    view.Sort = "Update Date ASC";
                    dt = view.ToTable();

                    if (dt.Rows.Count > 0)
                    {
                        // Remove unnecessary columns
                        DataColumnCollection dcCollection = dt.Columns;
                        string[] columnsToRemove = { "ID", "CustomerID", "Print", "Pay it", "Ship it", "Add Status" };
                        foreach (var column in columnsToRemove)
                        {
                            if (dcCollection.Contains(column))
                                dcCollection.Remove(column);
                        }

                        // Set up SaveFileDialog
                        SaveFileDialog sfd = new SaveFileDialog
                        {
                            Filter = "Excel files (*.xlsx)|*.xlsx|All files (*.*)|*.*",
                            FilterIndex = 1,
                            RestoreDirectory = true,
                            InitialDirectory = Environment.GetFolderPath(Environment.SpecialFolder.Personal)
                        };

                        // Show SaveFileDialog and export data to Excel
                        if (sfd.ShowDialog() == DialogResult.OK)
                        {
                            try
                            {
                                Cursor.Current = Cursors.WaitCursor;

                                // Export to Excel using ClosedXML
                                using (XLWorkbook wb = new XLWorkbook())
                                {
                                    wb.Worksheets.Add(dt, "Sheet1");
                                    wb.SaveAs(sfd.FileName);
                                }
                                MessageBox.Show("Export Successfully");
                                // Open the Excel file in Excel
                                var app = new Microsoft.Office.Interop.Excel.Application
                                {
                                    Visible = true
                                };
                                app.Workbooks.Open(sfd.FileName, ReadOnly: false);
                            }
                            catch (Exception ex)
                            {
                                MessageBox.Show($"Error during export: {ex.Message}");
                            }
                            finally
                            {
                                Cursor.Current = Cursors.Default;
                            }
                        }
                    }
                    else
                    {
                        MessageBox.Show("No Record Found");
                    }
                }
                else
                {
                    MessageBox.Show("You can not access");
                }


            }
            catch (Exception ex)
            {
                ClsCommon.WriteErrorLogs("Form:FrmCustomerCenter, Function :btnInvExport_Click. Message:" + ex.Message);
                MessageBox.Show("Error:" + ex.Message);
            }
        }
        private void btnInvoicePrint_Click(object sender, EventArgs e)
        {
            string CUSTOMER = "";
            decimal OPENBALANCE = 0;
            CUSTOMER = dgvCustomerList.Rows[0].Cells["CustomerName"].Value.ToString();
            //OPENBALANCE = Convert.ToDecimal(dgvCustomerList.Rows[0].Cells["BalanceTotal"].Value);

            DataTable dt = new DataTable();
            dt.Columns.Add("CUSTOMER", typeof(string));
            //dt.Columns.Add("OPENBALANCE", typeof(decimal));

            foreach (DataGridViewColumn column in dgvInvoiceList.Columns)
            {
                dt.Columns.Add(column.HeaderText);
            }
            foreach (DataGridViewRow row in dgvInvoiceList.Rows)
            {
                if (row.IsNewRow) continue;

                DataRow dataRow = dt.NewRow();
                dataRow["CUSTOMER"] = CUSTOMER;
                //dataRow["OPENBALANCE"] = OPENBALANCE; 
                foreach (DataGridViewCell cell in row.Cells)
                {
                    if (cell.FormattedValue != null)
                    {
                        dataRow[cell.ColumnIndex + 1] = cell.FormattedValue.ToString();
                    }
                }
                dt.Rows.Add(dataRow);
            }
            if (dt.Rows.Count > 0)
            {
                PrintInvoiceCustCent cryRptInvoiceReport = new PrintInvoiceCustCent(); //reportname
                cryRptInvoiceReport.SetDataSource(dt);
                //cryRptInvoiceReport.SetParameterValue("CUSTOMER", CustomerName);
                FrmCrystalReportViewer crViewer = new FrmCrystalReportViewer();
                crViewer.Text = "Invoice Report";
                crViewer.crystalReportViewer.ReportSource = cryRptInvoiceReport;
                crViewer.btnPrint.Visible = true;
                crViewer.crystalReportViewer.ShowPrintButton = false;
                crViewer.crystalReportViewer.ShowPrintButton = false;
                crViewer.Visible = false;
                crViewer.crystalReportViewer.PrintReport();
                //crViewer.Visible = true;
            }
            else
            {
                MessageBox.Show("Record not Found");
            }
        }
